			for (int i = 1; i < 9; i++) {
				boolean spot_ok = false;
				int do_counter = 0;
				do {
					if(i < 7) {
						for (int j = 0; j < 2; j++) {
							game.markers[j][i] = game.dice.throwdice(1, game.boardside);
						}	
					}
					else {
						int[] newborderspot = new int[2];
						newborderspot = game.borderSpot();
						game.markers[0][i] = newborderspot[0];
						game.markers[1][i] = newborderspot[1];
						//System.out.println("marker "+i+" is at "+game.markers[0][i]+", "+game.markers[1][i]);
						spot_ok = true;
					}
					if(spot_taken[game.markers[0][i]][game.markers[1][i]]) spot_ok = false;
					else {
						double dist_from_house = Math.sqrt(Math.pow(game.markers[0][i], game.markers[0][0]) + Math.pow(game.markers[1][i], game.markers[1][0]));
						if(i == 1 && dist_from_house < 4.2) spot_ok = true;
						if(i == 2 && dist_from_house > 7) spot_ok = true;
						if(i == 3 && dist_from_house < 3) spot_ok = true;
						if(i == 4) spot_ok = true;
						if(i == 5 && dist_from_house > 7) spot_ok = true;
						if(i == 6 && dist_from_house > 7) spot_ok = true;
					}				
					
					if(i >= 7 && game.markers[0][i] == game.forest_entry_x && game.markers[1][i] == game.forest_entry_y) spot_ok = false;
					
					do_counter++;
					if(do_counter > 50) {
						game.masterStringOut("...");
						do {
							for (int j = 0; j < 2; j++) {
								game.markers[j][i] = game.dice.throwdice(1, game.boardside);
							}
							if(spot_taken[game.markers[0][i]][game.markers[1][i]]) spot_ok = false;
							else spot_ok = true;
						}while(!spot_ok);
					}
				}while(!spot_ok);
				spot_taken[game.markers[0][i]][game.markers[1][i]] = true;
			}
			
			
