											//							  |											|
											//		 			  samegang / not							samegang / not
											//						|		  |			       					|       |
											//			 userleads/doesn't    C.	        		userleads/doesn't   youknowhim/don't
											//			   B.       B.						             D.     E.         F.        G.
											//					  							
											//	A.  The dragon attacks!
											//  B.	same as A
