										if(movement[0][game.user] + x_flip > 0 && movement[0][game.user] + x_flip < game.boardside + 1) movement[2][game.user] = movement[0][game.user] + x_flip;
										if(movement[1][game.user] + y_flip > 0 && movement[1][game.user] + y_flip < game.boardside + 1) movement[3][game.user] = movement[1][game.user] + y_flip;

