								add_to_letters_dead_here = "(" + getAlphabet(number_of_bodies_marked) + ".)";
								int extra_spaces_dead_here = add_to_dead_here.length() + 6 - add_to_letters_dead_here.length();
								for(int z = 0; z < extra_spaces_dead_here; z++) {
									add_to_letters_dead_here = add_to_letters_dead_here + " ";
								} 
								if(army[l].how_buried() < 30) add_to_dead_here = wordBury(add_to_dead_here, army[l].how_buried());
								dead_here = dead_here + add_to_dead_here + "      ";
								letters_dead_here = letters_dead_here + add_to_letters_dead_here;
								number_of_bodies_marked++;
