// civil war 1-on-1:  we select sides based on loyalties, with ONE person on each side to start...
// taunting we select sides based on multiple parties on each side to start...
	
	// ********************   C I V I L  W A R    *************************

	public void civilWar(int numa, int numb) {
		int[][] nums = new int[2][2];
		nums[0][0] = numa;
		nums[1][0] = numb;
		nums[0][1] = -1;
		nums[1][1] = -1;
		
		civilWar(nums);
	}
	
	public void civilWar(int[][] nums) {
		
//		masterStringOut("**** Starting civil war at "+army[numa].getx()+", "+army[numa].gety());
		
		int numa = nums[0][0];
		int numb = nums[1][0];
				
		//which gang is this? 
		int civilwargang = army[numa].getaffiliation();
	
		//count heads and advance the clock
		int number_in_gang = 0;
		for(int i = 0; i < armysize; i++) {
			if (army[i].getaffiliation() == civilwargang && army[i].gethealth() > 0) {
				number_in_gang++;
				army[i].changeround_clock(3);
			}
		}
		
		int sidechoice;
		int foechoice;
		int friendnumber;
		int foenumber;

		//quick exit longhouse, get text level, gang number, and battle location
		prepBattle_partA_first_fields(numa, numb);
		boolean user_placed = false;
		boolean[] already_placed = new boolean[armysize];
		boolean need_hit_enter_break = false;
		for(int i = 0; i < armysize; i++) {
			already_placed[i] = false;
		}		
		
		//here's where the real side-counting and array-making is happening for the civil war method.
		//we'll make the civil_war array, then count the pets and make the main war array. 
		int[][] civil_war = new int[2][number_in_gang];
		for(int i = 0; i < 2; i++) {

			for(int j = 0; j < number_in_gang; j++) civil_war[i][j] = -1;

			side_count[i] = 0;
			for(int j = 0; j < number_in_gang; j++) {
				if(j < nums[i].length) {
					if(nums[i][j] > -1 && nums[i][j] < armysize) {
						civil_war[i][side_count[i]] = nums[i][j];
						//System.out.println("civil_war["+i+"]["+side_count[i]+"] = "+civil_war[i][side_count[i]]);						
						side_count[i]++;
						already_placed[nums[i][j]] = true;
						if(nums[i][j] == user) user_placed = true; 
					}
				}
			}
//			System.out.println("**** 11842 side count of "+i+" is "+side_count[i]);				
		}
		
		
//[]()
		boolean user_rebuffed = false;
		
		//now, who else is joining? Anyone within three will join unless there's someone else to cling to.
		//run through all players.
		for(int i = 0; i < humansize; i++) {
			if(army[i].getaffiliation() == civilwargang && i != user) {
				if(army[i].gethealth() > 0 && army[i].ishere(battle_x, battle_y)) {

					boolean[] he_takes_side = new boolean[2];
					he_takes_side[0] = false;
					he_takes_side[1] = false;

					if(!already_placed[i]) {
					
						int c = 0;
						
						//takes a side?
						//do loop iterates twice, with c = 0 and then c = 1
						do {
						
							int num = (c == 0) ? numa : numb; 
							int othernum = (c == 0) ? numb : numa;
							
							//within 3?
							if (army[i].getfriend(num) <= 3) {
								he_takes_side[c] = true;
								//run through all players again.
								for(int j = 0; j < humansize; j++) {
									if(army[j].getaffiliation() == civilwargang && j != numa && j != numb && j != i) {
										if(army[j].gethealth() > 0 && army[j].ishere(battle_x, battle_y)) {
											//i does not take a side if there exists j, such that j is not as keen on num and i and j are pals.
											if(army[j].getfriend(num) > 3 && army[i].getfriend(j) <= 5) he_takes_side[c] = false;
										}
									}
								}
							}
								
		//					OR: i must join if he particularly likes num, or hates num's opponent.
							if(army[i].getfriend(num) == 0) he_takes_side[c] = true;
							if(army[i].getfriend(othernum) > 40 && army[i].getfriend(num) < 20) he_takes_side[c] = true;
						
							c++;
						
						} while(c <	2);
						
						if(he_takes_side[0] && he_takes_side[1]) {
							he_takes_side[0] = false;
							he_takes_side[1] = false;
							if(battletext > 1) masterStringOut(army[i].getname()+":  \"Please, "+army[numa].getname()+" and "+army[numb].getname()+"! You are both my friends!");
						}
						
						//i joins a if there were no back-up cronies.
						for(c = 0; c < 2; c++) {
							int num = (c == 0) ? numa : numb;
							if(he_takes_side[c]) {
								civil_war[c][side_count[c]] = i;
								//System.out.println("civil_war["+c+"]["+side_count[c]+"] = "+civil_war[c][side_count[c]]);
								if(i == user) user_placed = true;
								side_count[c]++;
								already_placed[i] = true;
								if(battletext > 1) {
									masterStringOut(army[i].getname()+" rushes to "+army[num].getname()+"'s side!");
									Wait.manySec(1);
									need_hit_enter_break = true;
								}
							}
//							System.out.println("**** 11911 side count of "+c+" is "+side_count[c]);				
						}
					}
					
					//pets joining?
					for(int c = 0; c < 2; c++) {
						int num = (c == 0) ? numa : numb;
						if(he_takes_side[c] || i == num) {
							int mypet_counter = 1;
							int ipet = -1;
							
							do {
								ipet = idMyPet(i, mypet_counter);
								if(ipet > -1) {
									pets_who_fight.get(c).add(ipet);
									if(battletext > 1) {
										String next_pet_msg = "";
										if(army[user].getfriend(ipet) > -1)next_pet_msg += army[ipet].getname()+": ";
										if(army[ipet].getspecies().compareToIgnoreCase("cat") == 0) next_pet_msg += "\"RRARRRRhhhhssss!\""; 
										if(army[ipet].getspecies().compareToIgnoreCase("dog") == 0) next_pet_msg += "\"BARK BARK BARK ! BARK BARK BARK BARK !\""; 
										masterStringOut(next_pet_msg);
										need_hit_enter_break = true;
									}
									mypet_counter++;
								}
							} while (ipet > -1);
						}	
					}
				}
			}
			
			//finally, if the user is not a or b, but a gang member, he may want to join in...
			if(i == user && battletext > 1 && !user_placed && !just_a_movie && army[user].gethealth() > 0 && army[user].ishere(battle_x, battle_y) && army[user].getaffiliation() == civilwargang) {
				masterStringOut("And you, "+army[user].getname()+"? Do you take a side in this disagreement?");
				String yn_choice = ynChoice();
				if (yn_choice.compareToIgnoreCase("y") == 0) {
					masterStringOut("Whose side are you on?");
					String name_choice = "null";
					do {
						masterStringOut("\n[  "+army[numa].getname()+"     "+army[numb].getname()+"  ]");
						name_choice = stringInput();
					} while (!nameMatchup(12014, name_choice, army[numa].getname()) && !nameMatchup(120140, name_choice, army[numb].getname()));
								
					sidechoice = (nameMatchup(12016, name_choice, army[numa].getname())) ? 0 : 1;
					foechoice =  (nameMatchup(12017, name_choice, army[numa].getname())) ? 1 : 0;
					friendnumber = (sidechoice == 0) ? numa : numb;
					foenumber = (sidechoice == 0) ? numb : numa;
									
					army[friendnumber].changefriend(user, -20);
					army[foenumber].changefriend(user, 30);
	
					if(army[friendnumber].getdevil_target() != foenumber && army[foenumber].getdevil_target() != friendnumber) {
						masterStringOut(army[friendnumber].getname()+": \"Yar, that's right! A friend to the end!\"");
						masterStringOut(army[foenumber].getname()+": \"Graarrrr!\"");
						need_hit_enter_break = true;
						
						civil_war[sidechoice][side_count[sidechoice]] = user;
						//System.out.println("civil_war["+sidechoice+"]["+side_count[sidechoice]+"] = "+civil_war[sidechoice][side_count[sidechoice]]);
						user_placed = true;
						already_placed[user] = true;
						side_count[sidechoice]++;
							
//						System.out.println("**** 11971 side count of "+sidechoice+" is "+side_count[sidechoice]);				


						int mypet_counter = 1;
						int ipet = -1;
								
						do {
							ipet = idMyPet(user, mypet_counter);
							if(ipet > -1) {
								pets_who_fight.get(sidechoice).add(ipet);
								mypet_counter++;
							}
						} while (ipet > -1);
	
					}
					if(army[friendnumber].getdevil_target() == foenumber) {
						user_rebuffed = true;
						masterStringOut(army[friendnumber].getname()+": \"Watch it, get out of my way!!\"");
						masterStringOut(army[friendnumber].getname()+" rebuffs your assistance- while "+army[foenumber].getname()+" marks well your perfidy!");
						masterStringOut(army[foenumber].getname()+": \"You traitor!!\"");
						need_hit_enter_break = true;
					}				
				}				
				else {
					masterStringOut("You back off to the sidelines and watch...");
					Wait.manySec(2);
				}
			}
		}//end of the humansize loop and making the civilwar array.
		
		//we can set "number_of_columns" now and make the real war array.
		
		//we are only adding in the pets if this isn't a duel.
		if(side_count[0] > 1 || side_count[1] > 1) {
			for(int each = 0 ; each < 2; each++) {
				side_count[each] += pets_who_fight.get(each).size();
//				System.out.println("**** 12006 side count of "+each+" is "+side_count[each]);				
			}
		}
		

		number_of_columns = Math.max(side_count[0], side_count[1]);
				
		//		if(number_of_columns < side_count[0] || number_of_columns < side_count[1]){
		//			masterStringOut("number_of_columns = "+number_of_columns+";  side count 0 = "+side_count[0]+";  side count 1 = "+side_count[1]);
		//		}
		
		
		//  count up the pets that join in. 
		//  DUEL, w/pets:  The cat/dog/animals (or list of names), understanding its/their place, do/does not interfere in the duel.
		//	Duel, no pets, rebuff:  The two rivals fight alone!
		//	Duel, no pets, no rebuff:  No one comes to the aid of the two rivals... they fight alone!
		//  BATTLE w/pets: The cat/dog/animals (or list of names), seeing the open melee, join in to protect its/their master(s)!
		//	battle, no pets, rebuff: No message
		//  battle, no pets, no rebuff: No message


		if(pets_who_fight.get(0).size() > 0 || pets_who_fight.get(1).size() > 0) {
			number_of_columns += Math.max(pets_who_fight.get(0).size(), pets_who_fight.get(1).size());
		}

		war = new int[2][number_of_columns];

		war_names = new String[2][number_of_columns];
		
		war_names_for_dialogue = new String[2][number_of_columns];
		
		out_of_the_fight = new boolean[2][number_of_columns];

		scar = new int[2][number_of_columns];

		user_is_here = army[user].ishere(battle_x, battle_y);		
		
		prepBattle_partA_1_set_arrays_based_on_number_of_columns();

		for(int i = 0; i < 2; i++) {
			for(int j = 0; j < number_of_columns; j++) {
				war[i][j] = -1;
				scar[i][j] = 0;
				war_names[i][j] = "none";
				war_names_for_dialogue[i][j] = "none";
			}
		}
		
		//round two of placements (into war this time)
		for(int i = 0; i < armysize; i++) {
			already_placed[i] = false;
		}		
		
		//humans pile in:
		int human_participants = 0;
		int strange_humans = 0;
		for(int i = 0; i < 2; i++) {
			for(int j = 0; j < number_of_columns; j++) {
				if(j < civil_war[i].length) {
					//System.out.println("**** 12038 civil_war["+i+"]["+j+"] =  "+civil_war[i][j]);
					war[i][j] = civil_war[i][j];
					if(war[i][j] > -1) {
						if(!already_placed[war[i][j]]) {
							if(war[i][j] == user) {
								user_placed = true;
								battletext = 3;
							}
							human_participants++;
							war_names[i][j] = army[war[i][j]].getname();
							war_names_for_dialogue[i][j] = war_names[i][j];
							if(army[user].getfriend(war[i][j]) == -1) {
								war_names[i][j] = "stranger";
								war_names_for_dialogue[i][j] = "a stranger";
								strange_humans++;
							}
							scar[i][j] = army[war[i][j]].gethealth();
							out_of_the_fight[i][j] = false;
							already_placed[war[i][j]] = true;
						}
					}
				}
			}
		}


		//a pet might join...  (This is just dialogue)
		if(pets_who_fight.get(0).size() > 0 || pets_who_fight.get(1).size() > 0) {
			if(battletext > 1) {
				String pet_join_msg = "";
				//a single pet...
				if(pets_who_fight.get(0).size() + pets_who_fight.get(1).size() == 1) {
					//do we know the name?
					for(int try_pet_side = 0; try_pet_side < 2; try_pet_side++) {
						if(pets_who_fight.get(try_pet_side).size() == 1) {
							if(army[user].getfriend(pets_who_fight.get(try_pet_side).get(0)) > -1) pet_join_msg += army[pets_who_fight.get(try_pet_side).get(0)].getname();
							else pet_join_msg += "The "+army[pets_who_fight.get(try_pet_side).get(0)].getspecies();
						}
					}
				}
				else pet_join_msg = "The animals";
				//A duel...
				if (human_participants == 2) {
					//a single pet...
					if(pets_who_fight.get(0).size() + pets_who_fight.get(1).size() == 1) pet_join_msg+=", understanding its place, does not interfere in the duel.";
					else pet_join_msg+=", understanding their place, do not interfere in the duel.";
				}
				else {
					if(pets_who_fight.get(0).size() + pets_who_fight.get(1).size() == 1) pet_join_msg+=", seeing the open melee, joins in to protect its master!";
					else pet_join_msg+=", seeing the open melee, join in to protect their masters!";
				}
				masterStringOut(pet_join_msg);
				need_hit_enter_break = true;
			}		

		}
			
		//get those pets in there...		
		int strange_cats = 0;
		int strange_dogs = 0;
		if(human_participants > 2) {
			for(int i = 0; i < 2; i++) {
				for(int j = 0; j < pets_who_fight.get(i).size(); j++) {
		k_loop:		for(int k = 0; k < number_of_columns; k++) {
						if(war[i][k] == -1 && pets_who_fight.get(i).get(j) > -1) {
							war[i][k] = pets_who_fight.get(i).get(j);
							war_names[i][k] = army[pets_who_fight.get(i).get(j)].getname();
							if(!army[pets_who_fight.get(i).get(j)].has_name()) {
								war_names[i][k] = army[pets_who_fight.get(i).get(j)].getspecies();
								if(army[pets_who_fight.get(i).get(j)].getspecies().compareToIgnoreCase("dog") == 0) strange_dogs++;
								if(army[pets_who_fight.get(i).get(j)].getspecies().compareToIgnoreCase("cat") == 0) strange_cats++;
							}
							war_names_for_dialogue[i][k] = army[pets_who_fight.get(i).get(j)].getname_lower();
							scar[i][k] = army[war[i][k]].gethealth();
							out_of_the_fight[i][k] = false; 
							already_placed[war[i][k]] = true;
							break k_loop;
						}
					}
				}
			}
		}
		
		if(battletext == 3) addIndicesToNonBeastNames(strange_humans, 0, strange_dogs, strange_cats);
		
		if(human_participants == 2) {
			if(battletext > 1) {
				if(user_rebuffed) masterStringOut("The two rivals fight alone!");
				else masterStringOut("No one comes to the aid of the two rivals... they fight alone!");
				if(!user_placed) Wait.manySec(1);
				else need_hit_enter_break = true;
			}
		}
		
		if(need_hit_enter_break) hitEnter(12149);
		
		if(human_participants == 2) Duel(numa, numb, true);
		else {
			prepBattle_partC_gangwar_opening_dialogue();
			prepBattle_partE_setting_last_fields();				
			if(battletext == 1) {
				masterStringOut("Other gang members get involved in the dispute... It's a battle of "+side_count[0]+" against "+side_count[1]+"!");
				Wait.manySec(2);
			}
			
			// for(int rrev = 0; rrev < 2; rrev++) {
			// 	for(int crev = 0; crev < number_of_columns; crev++) {
			// 		System.out.println(" war["+rrev+"]["+crev+"] =  "+war[rrev][crev]+";  out_of_the_fight = "+out_of_the_fight[rrev][crev]);
			// 	}
			// }

			Battle();
		}

	}// end civil war			



	//Battle Prep Methods

	//called by prepBattle:
	public void countSidesForBattle(int numa, int numb) {	
		int[] nums = new int[2];
		nums[0] = numa;
		nums[1] = numb;

		//if either side leader is a zombie, we set "zombie_fight" to that side.
		for(int q = 0; q < 2; q++) {
			if(nums[q] > -1) {
				if(army[nums[q]].is_zombie()) zombie_fight = q;
			}
		}
		int alpha_for_no_names = 0;
		String diffxymessage = "**** 11671 diff xy: ";
		boolean display_diffxymessage = false;
		int x_for_diffxy = -1;
		int y_for_diffxy = -1;
		for(int q = 0; q < 2; q++) {
			if(q == 1 && they_fight_beasts) continue;
			//find army members who belong in the battle array.
			for(int i = 0; i < armysize; i++) {
				if(army[i].ishere(battle_x, battle_y) && army[i].gethealth() > 0 && army[i].getx() != house_coord) {
					//find humans...
					if(i < humansize) {
						//count zombies...
						if(q == zombie_fight && army[i].is_zombie()) {
							zombies_who_fight.add(i);
							if(x_for_diffxy == -1) {
								x_for_diffxy = army[i].getx();
								y_for_diffxy = army[i].gety();
							}
							else if(x_for_diffxy != army[i].getx() || y_for_diffxy != army[i].gety()) display_diffxymessage = true;
							diffxymessage+= "zombie at "+army[i].getx()+", "+army[i].gety()+" ";
							side_count[q]++;
							if(user == i) battletext = 3;
						}
						//count non zombies...
						else {
							if(i == nums[q]) {
								side_count[q]++;
								if(user == i) battletext = 3;
							}
							else if(sameGang(i, nums[q])) {
								side_count[q]++;
								if (user == i) battletext = 3;
							}
						}
					}
					//find pets...
					else {
						if(army[i].getmasters_number() != -1) {
							if(army[army[i].getmasters_number()].ishere(battle_x, battle_y)) {
								if(army[i].getmasters_number() == nums[q] || sameGang(army[i].getmasters_number(), nums[q])) { 
									pets_who_fight.get(q).add(i);
//									if(!army[i].has_name()) {
//										army[i].setname(army[i].getspecies()+" ("+getAlphabet(alpha_for_no_names)+")");
//										alpha_for_no_names++;
//									}
									if(x_for_diffxy == -1) {
										x_for_diffxy = army[i].getx();
										y_for_diffxy = army[i].gety();
									}
									else if(x_for_diffxy != army[i].getx() || y_for_diffxy != army[i].gety()) display_diffxymessage = true;
									diffxymessage+= "pet at "+army[i].getx()+", "+army[i].gety()+" ";
									side_count[q]++;
								}
							}
						}
					}
				}
			}
		}
		if(display_diffxymessage) {
			//System.out.println("**** Issue with bad war array list placement !  12616  "+diffxymessage);
			hitEnter(11732);
		}
		//do we want to set the name to the species instead of "none" ?
//		if(alpha_for_no_names == 1) {
//			for(int getpet = 0; getpet < pets_who_fight.size; getpet++) {
//				if(army[pets_who_fight.get(getpet)].getname().endsWith(")")) army[pets_who_fight.get(getpet)].setname("none");
//			}
//		}
		
		if (side_count[0] == 0) side_count[0] = 1;
		if (side_count[1] == 0) side_count[1] = 1;
		
		if(they_fight_beasts) side_count[1] = beast_number;
		
		//finally, we know the number of columns (the maximum of the two).
		number_of_columns = Math.max(side_count[0], side_count[1]);
	}
	
	public void makeWarArray(int army_a, int army_b) {
	
		int[] nums = new int[2];
		nums[0] = army_a;
		nums[1] = army_b;
		
		war = new int[2][number_of_columns];
		
		war_names = new String[2][number_of_columns];
		
		war_names_for_dialogue = new String[2][number_of_columns];
		
		out_of_the_fight = new boolean[2][number_of_columns];

		user_is_here = army[user].ishere(battle_x, battle_y);
		int number_of_strangers = 0;
		int number_of_strange_corpses = 0;
		int number_of_strange_dogs = 0;
		int number_of_strange_cats = 0;

		
		for(int i = 0; i < 2; i++) {
			for(int j = 0; j < number_of_columns; j++) {
				war[i][j] = -1;
				out_of_the_fight[i][j] = true;
				war_names[i][j] = "none";
				war_names_for_dialogue[i][j] = "none";
			}
		}
		
		boolean[] already_placed = new boolean[armysize];
		for(int i = 0; i < armysize; i++) {
			already_placed[i] = false;
		}
				
		int best_health;
		int player_with_best_health;
		int more_entering_zombies = -1;
		
		//place zombie zero
		for(int nummy = 0; nummy < 2; nummy++) {
			if(nums[nummy] > -1) {
				if(army[nums[nummy]].is_zombie()) {
					war[zombie_fight][0] = nums[nummy];
					already_placed[nums[nummy]] = true;
					out_of_the_fight[zombie_fight][0] = false;
					more_entering_zombies++;
				}
			}
		}
		//place zombies				
		if(zombie_fight != -1) {
			for(int j = 0; j < armysize; j++) {
				if(army[j].is_zombie()) {
					if(army[j].ishere(battle_x, battle_y) && army[j].gethealth() > 0 && !already_placed[j]) {
						boolean yes_z_join = false;
						if(j != user) yes_z_join = (dice.throwdice(1,2) == 1) ? true : false;
						else {
							masterStringOut("Do you join the battle?");
							yes_z_join = ynChoiceBoolean();
						}
						if(yes_z_join) {
		get_war_spot_loop:	for(int i = 0; i < number_of_columns; i++) {
								if(war[zombie_fight][i] == -1) {
									war[zombie_fight][i] = j;
									out_of_the_fight[zombie_fight][i] = false;
//									scar[zombie_fight][i] = army[war[zombie_fight][i]].gethealth();
									if(j != user) more_entering_zombies++;
									//masterStringOut("army["+j+"] is undead, also joining at "+battle_x+", "+battle_y);
									already_placed[j] = true;
									break get_war_spot_loop;
								}	
							}
						}
					}
				}
			}
			if(they_fight_beasts && zombie_fight > -1) {
				//System.out.println("**** 15208 battle at "+battle_x+", "+battle_y+", they_fight_beasts true, zombie fight is "+zombie_fight+"; who is a zombie here?");
				for(int zoma = 0; zoma < number_of_columns; zoma++) {
					String zomline = "";
					if(war[0][zoma] < 0) zomline += "----";
					else {
						zomline += war[0][zoma];
						if(army[war[0][zoma]].is_zombie()) zomline += "true";
						else zomline += "false";
					}
					zomline += "    "; 
					if(war[1][zoma] < 0) zomline += "----";
					else zomline += army[war[1][zoma]].is_zombie();
					//System.out.println("**** "+zomline);
				}
			}
			//message about zombies jumping in
			if(battletext > 1 && !they_fight_beasts) {
				if(more_entering_zombies == 1) masterStringOut("Another walking corpse joins the fray!");
				if(more_entering_zombies > 1 && more_entering_zombies < 5) masterStringOut("More walking corpses wander into the fight!");
				if(more_entering_zombies >= 5) masterStringOut("The battle is growing large- walking corpses are swarming in!");
				if(more_entering_zombies > 0) hitEnter(11286);
			}
		}

		//place humans 
		for(int q = 0; q < 2; q++) {
			if(q == 1 && they_fight_beasts) continue;
			if(q == zombie_fight) continue;
			for(int i = 0; i < number_of_columns; i++) {
				best_health = 0;
				player_with_best_health = -1;
				if(i < side_count[q] - pets_who_fight.get(q).size()) {
					for(int j = 0; j < humansize; j++) {
						if(army[j].ishere(battle_x, battle_y) && army[j].gethealth() > 0 && !already_placed[j] && !army[j].is_zombie()) {
							if((sameGang(j, nums[q]) || j == nums[q]) && army[j].gethealth() > best_health) {
								best_health = army[j].gethealth();
								player_with_best_health = j;
							}
						}
					}
//					if(player_with_best_health == -1) masterStringOut("**** 11418 player_with_best_health == -1; i == "+i+"; side_count[q] == "+side_count[1]+"; pets_who_fight.get(q).size() == "+pets_who_fight.get(q).size());
					if(player_with_best_health != -1) {
						war[q][i] = player_with_best_health;
						out_of_the_fight[q][i] = false;
						already_placed[player_with_best_health] = true;
					}
				}
			}
		}
		
		//place pets
		for(int q = 0; q < 2; q++) {
			if(pets_who_fight.get(q).size() > 0) {
				for(int pwf = 0; pwf < pets_who_fight.get(q).size(); pwf++) {
					if(!already_placed[pets_who_fight.get(q).get(pwf)]) {
	find_col_loop:		for(int i = 0; i < number_of_columns; i++)	{
							if(war[q][i] == -1 && pets_who_fight.get(q).get(pwf) > -1) {
								war[q][i] = pets_who_fight.get(q).get(pwf);
								already_placed[pets_who_fight.get(q).get(pwf)] = true;
								out_of_the_fight[q][i] = false;						
								
								//pets jumping in message
								if(war[q][i] > -1) {
									if(battletext > 1) {
										String jump_in_message = "";
										if(army[user].getfriend(war[q][i]) > -1) jump_in_message = army[war[q][i]].getname();
										else jump_in_message = "A "+army[war[q][i]].getspecies();
										if(army[war[q][i]].hidden()) jump_in_message += ", who has been hiding nearby,";
										jump_in_message += " jumps in";
										if(army[user].getfriend(army[war[q][i]].getmasters_number()) > -1) jump_in_message += " to defend "+army[army[war[q][i]].getmasters_number()].getname();
										else jump_in_message += "to the fight";
										jump_in_message += "!";
										masterStringOut(jump_in_message);
										Wait.longBlip(4);
									}
									if(army[war[q][i]].getmasters_number() == user && !army[army[war[q][i]].getmasters_number()].does_player_perceive_this_pet(war[q][i])) {
										String returnmessage = army[user].getname()+": \"Hooray! You've come back to me";
										if(army[war[q][i]].has_name()) returnmessage += ", "+army[war[q][i]].getname()+"!\"";
										else returnmessage += "!\"";
										masterStringOut(returnmessage);
									}
									if(army[war[q][i]].getspecies().compareToIgnoreCase("cat")==0 && they_fight_beasts) {
										if(beast_type.compareToIgnoreCase("rat") == 0 || beast_type.compareToIgnoreCase("rattish man") == 0) {
											if(battletext > 1) {
												String special_attack_message = "";
												if(army[user].getfriend(war[q][i]) > -1) special_attack_message = army[war[q][i]].getname();
												else special_attack_message = "The "+army[war[q][i]].getspecies();
												masterStringOut(special_attack_message+" is sent into a murderous frenzy by the smell of "+beast_type+"!");
											}
											army[war[q][i]].high_battle(beast_type);
										}
									}
									
									//pets make memory of battle
									army[war[q][i]].make_memory("battle");
																	
								}
								
								break find_col_loop;
							}
						}
					}
				}
			}
		}
	
		if((pets_who_fight.get(0).size() > 0 || pets_who_fight.get(1).size() > 0) && battletext > 1) hitEnter(11343);
				
		//set up display names for all participants.
		if(user_is_here || battle_movies) {
			for(int rownames = 0; rownames < 2; rownames++) {
				for(int colnames = 0; colnames < number_of_columns; colnames++) {
					if(war[rownames][colnames] > -1) {
						if(army[user].getfriend(war[rownames][colnames]) > -1 && army[war[rownames][colnames]].has_name()) {
							war_names[rownames][colnames] = army[war[rownames][colnames]].getname();
							war_names_for_dialogue[rownames][colnames] = army[war[rownames][colnames]].getname();
							if(army[war[rownames][colnames]].is_zombie()) {
								war_names_for_dialogue[rownames][colnames] = "the walking corpse of " + war_names[rownames][colnames];
								war_names[rownames][colnames] += " (UNDEAD)";
							}						
						}
						else {
//							masterStringOut("*** setting up names for "+army[war[rownames][colnames]].getname());
							if(army[war[rownames][colnames]].getspecies().compareToIgnoreCase("human") == 0) {
//								masterStringOut("*** setting up names for "+army[war[rownames][colnames]].getname()+" stage 2");
								if(!army[war[rownames][colnames]].is_zombie()) {
//									masterStringOut("*** setting up names for "+army[war[rownames][colnames]].getname()+" stage 3");
									if(battletext == 3) {
										war_names[rownames][colnames] = "stranger";
										war_names_for_dialogue[rownames][colnames] = "the stranger";
									}
									if(battletext == 1) {
										war_names[rownames][colnames] = "a stranger";
										war_names_for_dialogue[rownames][colnames] = "a stranger";
									}
									number_of_strangers++;
								}
								else {
									if(battletext == 3) {
										war_names[rownames][colnames] = "UNDEAD";
										war_names_for_dialogue[rownames][colnames] = "the walking corpse";
									}
									if(battletext == 1) {
										war_names[rownames][colnames] = "a walking corpse";
										war_names_for_dialogue[rownames][colnames] = "a walking corpse";
									}									
									number_of_strange_corpses++;
								}
							}
							else {
								if(battletext == 3) {
									war_names_for_dialogue[rownames][colnames] = "the " + army[war[rownames][colnames]].getspecies();
									war_names[rownames][colnames] = army[war[rownames][colnames]].getspecies();
								}
								if(battletext == 1) {
									war_names_for_dialogue[rownames][colnames] = "a " + army[war[rownames][colnames]].getspecies();
									war_names[rownames][colnames] = "a "+army[war[rownames][colnames]].getspecies();
								}
							}
							if(army[war[rownames][colnames]].getspecies().compareTo("dog") == 0) number_of_strange_dogs++;
							if(army[war[rownames][colnames]].getspecies().compareTo("cat") == 0) number_of_strange_cats++;
						}
					}
				}
			}
		}
			

		//place beasts. We are assuming that they will be in row 1 every time. We are also adding our beasts to the army array, a radical 
		//new direction for this program. Be aware that in the main constructor method, the army array is now initiated to include humans, 
		//pets, and beasts, now all classified as "beings." Under "Being" we have "Beast" and "Player"; under "Player" we have "Human," "Dog" 
		//and "Cat." The integer "armysize" is the greater partition of the army array, with all players included; the integer "humansize" is a 
		//partition within "armysize," including humans only. Beyond armysize, there are 100 positions reserved for the beasts.
		
//		System.out.println("**** 12554 they_fight_beasts is "+they_fight_beasts+",  beast_fight is  "+beast_fight+", beast number is "+beast_number);
		  
		if(they_fight_beasts) {
			for(int i = 0; i < beast_number; i++) {
				if(beast_type.compareToIgnoreCase("rat") == 0) army[armysize + i] = new Rat(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("pig") == 0) army[armysize + i] = new Pig(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("snake") == 0) army[armysize + i] = new Snake(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("skeleton") == 0) army[armysize + i] = new Skeleton(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("devil") == 0) army[armysize + i] = new Devil(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("dragon") == 0) {
					army[armysize + i] = dragon[i];
					army[armysize + i].setarray_position(armysize + i);
				}
				if(beast_type.compareToIgnoreCase("spider") == 0) army[armysize + i] = new Spider(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("creeper") == 0) army[armysize + i] = new Creeper(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("gnome") == 0) army[armysize + i] = new Gnome(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("rattish man") == 0) army[armysize + i] = new Rattishman(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("butterfly") == 0) army[armysize + i] = new Butterfly(dice, armysize + i);
				if(beast_type.compareToIgnoreCase("tree") == 0) army[armysize + i] = new Tree(dice, armysize + i);
				
				//now, in the war array, we set the next position in row 1 equal to the index of our new bestial army member.
				war[beast_fight][i] = (armysize + i);
				//System.out.println("**** 12576 war[beast_fight][i]: i is "+i+", beast_fight is "+beast_fight+", war value is "+war[beast_fight][i]);
				out_of_the_fight[beast_fight][i] = false;
				//since the beasts are born without a position, and are not yet designed to move on the board, we need to set their positions.				
				army[war[beast_fight][i]].setxy(battle_x, battle_y);
				war_names[beast_fight][i] = beast_type;
				if(battletext == 3) war_names_for_dialogue[beast_fight][i] = "the "+ beast_type;
				if(battletext == 1) war_names_for_dialogue[beast_fight][i] = "a "+ beast_type;				
				if(beast_type.compareToIgnoreCase("snake") == 0 && army[war[beast_fight][i]].getname().contains("red")) {
					war_names[beast_fight][i] = "snake (RED)";
					if(battletext == 3) war_names_for_dialogue[beast_fight][i] = "the RED snake";
					if(battletext == 1) war_names_for_dialogue[beast_fight][i] = "a red snake";
				}	 
				if(beast_number > 1 && battletext > 1) {
					war_names[beast_fight][i] += " ("+getAlphabet(i)+".)"; 
					war_names_for_dialogue[beast_fight][i] += " ("+getAlphabet(i)+".)"; 
				} 
			}
		}
		
		addIndicesToNonBeastNames(number_of_strangers, number_of_strange_corpses, number_of_strange_dogs, number_of_strange_cats);
		
	}
	
	public void addIndicesToNonBeastNames(int number_of_strangers, int number_of_strange_corpses, int number_of_strange_dogs, int number_of_strange_cats) {
		
		//System.out.println("****  11279 adding indices to war names "+number_of_strangers+" "+number_of_strange_corpses+" "+number_of_strange_dogs+" "+number_of_strange_cats); 
		int number_of_strangers_indexed = 0;
		int number_of_strange_corpses_indexed = 0;
		int number_of_strange_dogs_indexed = 0;
		int number_of_strange_cats_indexed = 0;

		for(int i = 0; i < 2; i++) {
			for(int j = 0; j < number_of_columns; j++) {
				if(war[i][j] > -1) {
					if(army[user].ishere(battle_x, battle_y) && army[war[i][j]].gettype().compareTo("beast") != 0) {
						if(army[user].getfriend(war[i][j]) == -1 || !army[war[i][j]].has_name()) {
							if(army[war[i][j]].getspecies().compareTo("human") == 0) {
								if(!army[war[i][j]].is_zombie()) {
									if(number_of_strangers > 1) {
										if(battletext == 3) {
											war_names[i][j] += " ("+getAlphabet(number_of_strangers_indexed)+".)";
											war_names_for_dialogue[i][j] += " ("+getAlphabet(number_of_strangers_indexed)+".)";
										}
										number_of_strangers_indexed++;
									}
								} 
								else {
									if(number_of_strange_corpses > 1) {
										if(battletext == 3) {
											war_names[i][j] += " ("+getAlphabet(number_of_strange_corpses_indexed)+".)";
											war_names_for_dialogue[i][j] += " ("+getAlphabet(number_of_strange_corpses_indexed)+".)";
										}
										number_of_strange_corpses_indexed++;
									} 
								}
							}
							if(army[war[i][j]].getspecies().compareTo("dog") == 0) {
								if(number_of_strange_dogs > 1) {
									if(battletext == 3) {
										war_names[i][j] += " ("+getAlphabet(number_of_strange_dogs_indexed)+")";
										war_names_for_dialogue[i][j] += " ("+getAlphabet(number_of_strange_dogs_indexed)+")";
									}
									number_of_strange_dogs_indexed++;
								} 
							}
							if(army[war[i][j]].getspecies().compareTo("cat") == 0) {
								if(number_of_strange_cats > 1) {
									if(battletext == 3) {
										war_names[i][j] += " ("+getAlphabet(number_of_strange_cats_indexed)+")";
										war_names_for_dialogue[i][j] += " ("+getAlphabet(number_of_strange_cats_indexed)+")";
									}
									number_of_strange_cats_indexed++;
								} 
							}
						}
					}
				}
			}
		}
	}

	public void prepBattle_partA_first_fields(int army_a, int army_b) {

		if((army_a == user || army_b == user) && waiting_outside_house) quickExitLongHouse(army[user].getaffiliation()); 

		if (they_fight_beasts && beast_type.compareToIgnoreCase("dragon") == 0) {
			if(dragon[0].getx() == army[user].getx()  &&  dragon[0].gety() == army[user].gety()) battletext = 1;
//			battle_movies = true;
		}
		else if(samePlace(army_a, user)) {
			battletext = 1;
			if ((sameGang(army_a, user) || sameGang(army_b, user)) && army[user].gethealth() > 0) battletext = 2;
			if (army_a == user || army_b == user) battletext = 3;
		}

		if(battletext > 0) just_a_movie = false;
		if(battle_movies) battletext = 3; 

		
		//get battle location
		battle_x = army[army_a].getx();
		battle_y = army[army_a].gety();

//		if(just_a_movie) masterStringOut("**** Battle is taking place at "+battle_x+", "+battle_y+";  you are at "+army[user].getx()+", "+army[user].gety());

		//set the "gangs" on each side
		side_gang[0] = army[army_a].getaffiliation();
		if(they_fight_beasts) side_gang[1] = -1;
		else if(army_b != -1) side_gang[1] = army[army_b].getaffiliation();
		else printHuh(11581);
	}
	
	public void prepBattle_partA_1_set_arrays_based_on_number_of_columns() {
		will_run = new boolean[2][number_of_columns];
		leader_called_it = new boolean[2];
		out_of_the_fight = new boolean[2][number_of_columns];
		dead_record = new boolean[2][number_of_columns];
		lowhealth_record = new boolean[2][number_of_columns];	
		party_ran_round = new int[2];
		party_runs = new boolean[2];
		for(int i = 0; i < 2; i++) {
			party_ran_round[i] = -1;
			party_runs[i] = false;
			leader_called_it[i] = false;
			for(int j = 0; j < number_of_columns; j++) {
				will_run[i][j] = false;
				out_of_the_fight[i][j] = true;
				dead_record[i][j] = false;
				lowhealth_record[i][j] = false;
				if(j < 2) will_run[i][j] = false;
			}
		}
	}
	
	public void prepBattle_partB_beast_opening_dialogue(int army_a) {
		if(they_fight_beasts) {
			if(beast_type.compareToIgnoreCase("dragon") != 0) {
				if(battletext == 1) {
					if(side_count[0] == 1) {
						if(army[user].getfriend(army_a) > -1) masterStringOut(army[army_a].getname()+" is under attack!");
						else masterStringOut("A nearby stranger is under attack!");
					}
					else masterStringOut("An ambush on the gang nearby!");
				}
				else if(battletext > 1) {
					if(army[user].getround_clock() < 100) {
						if(beast_type.compareToIgnoreCase("rat") == 0) {
							if(beast_number < 10) masterStringOut("\nYou hear scurrying noises...");
							else masterStringOut("\nYou hear a growing din of squeaks and scratchings...");
						}
						if(beast_type.compareToIgnoreCase("pig") == 0) masterStringOut("\nYou hear a crashing sound...");
						if(beast_type.compareToIgnoreCase("snake") == 0) masterStringOut("\nYou hear a rustling...");
						if(beast_type.compareToIgnoreCase("skeleton") == 0) {
							if(beast_number < 10) masterStringOut("\nYou hear a dry clattering sound...");
							else masterStringOut("\nYou hear a steady beat of dry crunching, many feet marching together...");
						}
						if(beast_type.compareToIgnoreCase("devil") == 0) masterStringOut("\nYou smell something burning...");
						if(beast_type.compareToIgnoreCase("spider") == 0) masterStringOut("\nYou hear rapid clicking, getting louder...");
						if(beast_type.compareToIgnoreCase("creeper") == 0) masterStringOut("\nThere is a disgusting slurping sound...");
						if(beast_type.compareToIgnoreCase("gnome") == 0) masterStringOut("\n\"Hee hee hee !\" \nWho said that?!");
						if(beast_type.compareToIgnoreCase("rattish man") == 0) masterStringOut("\nUgh! There is a wet animal funk in the air...");
						if(beast_type.compareToIgnoreCase("butterfly") == 0) masterStringOut("\nAir is silently rushing over your back...");
						if(beast_type.compareToIgnoreCase("tree") == 0) masterStringOut("\nAn echoing groan... a shadow darkens over you...");
					}
					
					int speaker = user;
					if(army[user].getaffiliation() != 0) {
						for(int i = 0; i < armysize; i++) {
							if(army[i].getaffiliation() == army[user].getaffiliation()) {
								speaker = i;
								break;
							}
						}
					}
					String warning = "";
					if(speaker != user) warning = warning + army[speaker].getname()+":  \"";
					if(beast_type.compareToIgnoreCase("tree") != 0) { 
						if(beast_number == 1) warning = warning + beast_type.toUpperCase(); 
						if(beast_number > 1) warning = warning + getPluralForm(beast_type).toUpperCase();
					}
					else {
						warning = warning + "THE TREES";
						if(speaker != user) warning = warning + "! BEWARE THE TREES";
					}
					warning = warning + "!";
					if(speaker != user) warning = warning + "\"";
					if(army[user].getround_clock() < 100) Wait.longBlip(5);
					masterStringOut(warning);
					if(army[user].getround_clock() < 100) hitEnter(9747);
				}
				else if(army[user].ishere(forest_entry_x, forest_entry_y)) {
					if(battle_x >= boardside + 3 && battle_x <= boardside + 8) {
						masterStringOut("From within the forest, you hear crashing, clawing, and monstrous shrieks...");
					}
				}
			}			
			//if this is the dragon, the user nearby will hear it...
			else {
				int x_diff = battle_x - army[user].getx();
				int y_diff = battle_y - army[user].gety();
				if(x_diff == -1 && y_diff == 0) masterStringOut("You hear snarling and screaming to the West...");
				if(x_diff == 1 && y_diff == 0) masterStringOut("You hear snarling and screaming to the East...");
				if(x_diff == 0 && y_diff == -1) masterStringOut("You hear snarling and screaming to the North...");
				if(x_diff == 0 && y_diff == 1) masterStringOut("You hear snarling and screaming to the South...");
				if(battletext == 1) {
					if(side_count[0] == 1) {
						if(army[user].getfriend(army_a) > -1) masterStringOut(army[army_a].getname()+" is attacked by the hungry dragon! You can barely watch!");
						else masterStringOut("A nearby stranger is attacked by the hungry dragon! Will he survive?");
					}
					else masterStringOut("The gang nearby faces the onslaught of the hungry dragon! Oh dear!");
				}
			}
		}
	}

	public void prepBattle_partC_gangwar_opening_dialogue() {
		int x_diff = battle_x - army[user].getx();
		int y_diff = battle_y - army[user].gety();
		if(!army[user].in_the_forest()) {
			if(x_diff == -1 && y_diff == 0) masterStringOut("You hear shouting to the West...");
			if(x_diff == 1 && y_diff == 0) masterStringOut("You hear shouting to the East...");
			if(x_diff == 0 && y_diff == -1) masterStringOut("You hear shouting to the North...");
			if(x_diff == 0 && y_diff == 1) masterStringOut("You hear shouting to the South...");
		}
	}

	public void prepBattle_partC2_spooky_forest_opening_dialogue() {
		if(army[user].in_the_forest) {
			if(battle_x >= boardside + 3 && battle_x <= boardside + 8 && !army[user].ishere(battle_x, battle_y)) {
				int user_knows_him = -1;
	ukm_loop:	for(int rukm = 0; rukm < 2; rukm++) {
					for(int cukm = 0; cukm < number_of_columns; cukm++) {
						if(war[rukm][cukm] >= 0 && war[rukm][cukm] < humansize) {
							if(army[user].getfriend(war[rukm][cukm]) > -1) {
								if(!forest_aiees.contains(army[war[rukm][cukm]].getname())) {
									user_knows_him = war[rukm][cukm];
									break ukm_loop;
								}
							}
						}
					}
				}
				if(user_knows_him > -1) {
					masterStringOut("From somewhere deep in these woods, you hear horrible sounds... crashing, screaming... and maybe even a voice you recognize...");
					Wait.manySec(3);
					masterStringOut(army[user_knows_him].getname()+" (perhaps) :  \"AAaaaaieeeeee....   \"");
					Wait.manySec(2);
					forest_aiees.add(army[user_knows_him].getname());
				}
				else masterStringOut("From somewhere deep in these woods, you hear horrible sounds... crashing, screaming...");
			}
		}
	}

	
	public void prepBattle_partD_beast_bail_out(int army_a) {
		//see who bails out. (Let's stick to the way it was- we only have initial bail-outs if it's a beast fight.)		
		boolean[] first_bail = new boolean[number_of_columns];
		for(int i = 0; i < number_of_columns; i++) {
			first_bail[i] = false;
			if(war[0][i] > -1) {
				if(beast_type.compareToIgnoreCase("dragon") == 0 || (army[war[0][i]].getround_clock() >= 100 && !army[war[0][i]].is_he_leader())) {
					if(beast_type.compareToIgnoreCase("dragon") == 0) {
						if(war[0][i] != army_a) {
							if(war[0][i] == user) {
								masterStringOut("You have a choice, "+army[user].getname()+". You can either stand with your gang and fight this dragon, or you can bail on "+army[army_a].getname()+", whom the dragon has chosen as his next meal. Which is it?");
								String beast_choice1 = "null";
								do {
									masterStringOut("\n[ Fight      Run ]");
									beast_choice1 = stringInput();
								} while (beast_choice1.compareToIgnoreCase("fight") != 0 && beast_choice1.compareToIgnoreCase("run") != 0);
								if (beast_choice1.compareToIgnoreCase("run") == 0) {
									masterStringOut("You frantically run away in the first available direction...");
									if(army_a != user) masterStringOut(army[army_a].getname()+": \"YOU'D BETTER HOPE THIS DRAGON EATS ME, YOU @#^*@&!!!\"");
									hitEnter(11476);
									first_bail[i] = true;
									battletext = 0;
								}
							}
							else {
								if(army[war[0][i]].getloyalty() == 1 && side_count[0] < 8) first_bail[i] = true;
								if(army[war[0][i]].getloyalty() == 2 && side_count[0] < 6) first_bail[i] = true;
								if(army[war[0][i]].getloyalty() == 3 && side_count[0] < 5) first_bail[i] = true;
							}
						}
					}
					else {
						first_bail[i] = true;
						battletext = 0;
						masterStringOut("You slip away, leaving "+army[army_a].getname()+" to fend for himself.");
						hitEnter(9847);
					}
				}
			}
		}
		//now we have the runners actually run away.
		for(int i = 0; i < number_of_columns; i++) {
			if(first_bail[i] && war[0][i] > -1) {
				if(battletext > 0 && army[user].getfriend(war[0][i]) > -1) {
					masterStringOut(army[war[0][i]].getname()+" runs away!"); 
					Wait.manySec(1);
				}
				
				//this method places the player at (-5,-5) and establishes a new potential position.
				runWithoutLeader(war[0][i], -2, -2);
				army[war[0][i]].setaffiliation(0);
				
				for(int j = 0; j < number_of_columns; j++) {
					if(war[0][j] > -1) {
						if(!first_bail[j] && army[war[0][j]].getspecies().compareToIgnoreCase("human") == 0) {
							army[war[0][j]].setfriend(war[0][i], 200, turnclock, 12173);
						}
					}
				}

				//we turn off the war array position. 
				war[0][i] = (war[0][i] + 1) * -1;
				will_run[0][i] = true;
				out_of_the_fight[0][i] = true;
			}
		}
	}
	
	public void prepBattle_partE_setting_last_fields() {
		//advance roundclocks and set "yourrow and yourcolumn." also one last check for battletext- should it be 3?
		battletext = 0;
		if(army[user].ishere(battle_x, battle_y)) battletext = 1;
		scar = new int[2][number_of_columns];
		for(int i = 0; i < 2; i++) {
			if(i == 1 && they_fight_beasts) continue;
			for(int j = 0; j < number_of_columns; j++) {
				if(war[i][j] > -1 && zombie_fight != i) army[war[i][j]].changeround_clock(3);
				if(war[i][j] == user) {
					yourrow = i;
					yourcolumn = j;
					battletext = 3;
				}
				scar[i][j] = 0;
			}
		}
		//count number of attacks and set up battle_order; set scar array for later battle scars; players can also draw swords here.
		int[] max_player_attacks = new int[2];
		max_player_attacks[0] = 0;
		max_player_attacks[1] = 0;
		boolean max_attacks_message = false;
		for(int q = 0; q < 2; q++) {
			if(q == 1 && they_fight_beasts) continue;
			for(int i = 0; i < number_of_columns; i++) {
//				if(war[q][i] < -1) masterStringOut("**** 11809 war[q][i] == "+war[q][i]);
				if(war[q][i] > -1) {
					if(items[2][0].getowner() == war[q][i] && army[war[q][i]].gethealth() > 0 && !army[war[q][i]].sword_drawn()) {
//						if(battletext > 0 && army[user].getfriend(war[q][i]) > -1) masterStringOut(army[war[q][i]].getname()+" draws his sword!");
//						if(battletext == 3) hitEnter(11009);
						army[war[q][i]].draw_sword();
					}
					if(max_player_attacks[q] < army[war[q][i]].getnumber_of_attacks()) max_player_attacks[q] = army[war[q][i]].getnumber_of_attacks();
					if(army[war[q][i]].getnumber_of_attacks() > 1) {
						//masterStringOut("**** 12915 being "+war[q][i]+", species "+army[war[q][i]].getspecies()+" has "+army[war[q][i]].getnumber_of_attacks()+" attacks");
						max_attacks_message = true;
					}
//					if(army[war[q][i]].getnumber_of_attacks() == 0) masterStringOut("**** 12918 being "+war[q][i]+", species "+army[war[q][i]].getspecies()+" has 0 attacks");
					
					scar[q][i] = army[war[q][i]].gethealth();
				}
			}		
		}
		if(they_fight_beasts) {
bi_loop:	for(int bi = 0; bi < number_of_columns; bi++) {
				if(war[beast_fight][bi] > -1) {
					max_player_attacks[1] = army[war[beast_fight][bi]].getnumber_of_attacks();
					break bi_loop;
				}
			}
		}
		
		max_attacks = Math.max(max_player_attacks[0], max_player_attacks[1]);	

		//if(max_attacks_message) System.out.println("**** 12632 max_attacks = "+max_attacks);

		//if(max_player_attacks[0] > max_attacks || max_player_attacks[1] > max_attacks) System.out.println("**** 11578: battle at "+battle_x+", "+battle_y+":  we have max_player_attacks[0] at "+max_player_attacks[0]+", max_player_attacks[1] at "+max_player_attacks[1]+", and max_attacks at "+max_attacks);
//		for(int q = 0; q < 2; q++) {
//			for(int i = 0; i < number_of_columns; i++) {
//				if(war[q][i] > -1) {
//					if(army[war[q][i]].getnumber_of_attacks() > max_attacks) System.out.println("**** 11582: battle at "+battle_x+", "+battle_y+":  we have a player with number of attacks at "+army[war[q][i]].getnumber_of_attacks()+", and max_attacks at "+max_attacks);
//				}
//			}		
//		}		
	
		battle_order = new int[2][number_of_columns][max_attacks];
		
//		if(max_attacks == 0) masterStringOut("**** 12948 battle_order created with number_of_columns = "+number_of_columns+" and max_attacks = "+max_attacks);
	
		if(side_count[0] == 0) masterStringOut("side count 0 == 0");
		if(side_count[1] == 0) masterStringOut("side count 1 == 0");
			
	}	
	
