			//so, does anyone speak an incantation, or throw an apple? (Also we'll try to find a leader here)		
			for(int i = 0; i < 2; i++) {
				for(int j = 0; j < number_of_columns; j++) {
					if(war[i][j] > -1) {
						if(army[war[i][j]].gethealth() > 0 && !out_of_the_fight[i][j] && !army[war[i][j]].is_zombie()) {
							leader_for_running[i] = getLeader(war[i][j]);
							if(leader_for_running[i] == -1) leader_for_running[i] = war[i][j];
							if(war[i][j] != user) {
								if(army[war[i][j]].getincantation(0) > -1) {
									if(dice.throwdice(1, 100) <= 15) {
										if(dice.throwdice(1, 10) <= 6) uses_incantation[i][j] = 0;
										else uses_incantation[i][j] = 1;
									}
								}
								if(uses_incantation[i][j] == -1 && appleOwnershipCount(war[i][j]) > 0 && army[war[i][j]].knows_sparks()) {
									if(dice.throwdice(1, 100) <= 15 + side_count[-1*i + 1]) throws_apple[i][j] = true;
								}
							}
						}
					}
				}
			}

//		masterStringOut("**** Battle at "+battle_x+", "+battle_y+", line 12262");
				
