																if(army[war[m][q]].getloyalty() < 3) {
																	if(willHeRun(war[m][q], stillFighting(m) - 1, (int)(army[war[beast_fight][beast_rep]].getvalue() * stillFighting(beast_fight) / 30))) {
																		will_run[m][q] = true;
	//																	masterStringOut("**** 12504 for war["+m+"]["+q+"] we have willHeRun = true");
																	//	ran_round[m][q] = shitcounter;
																	}	 	
																}
