	public int stillFighting(int side) {
		int number_still_fighting = 0;
		for(int j = 0; j < number_of_columns; j++) {
			if(war[side][j] > -1) {
//				masterStringOut("***** stillFighting: we have war["+side+"]["+j+"] > -1");
				if(army[war[side][j]].gethealth() > 0 && !out_of_the_fight[side][j]) {
//					masterStringOut("***** stillFighting: we have war["+side+"]["+j+"] health > 0");
					if(army[war[side][j]].ishere(battle_x, battle_y)) number_still_fighting++;
//					else masterStringOut("war["+side+"]["+j+"] is at "+army[war[side][j]].getx()+", "+army[war[side][j]].gety()); 
				}
			}
		}
//		masterStringOut("**** stillFighting: side "+side+": we have "+number_still_fighting+" still fighting");
		return number_still_fighting;
	}
	
	public int stillAlive(int side) {
		int number_still_alive = 0;
		for(int j = 0; j < number_of_columns; j++) {
			if(war[side][j] > -1) {
				if(army[war[side][j]].gethealth() > 0) number_still_alive++;
			}
		}
		return number_still_alive;
	}

	public int stillDead(int side) {
		int number_still_dead = 0;
		for(int j = 0; j < number_of_columns; j++) {
			if(war[side][j] > -1) {
				if(army[war[side][j]].gethealth() <= 0) number_still_dead++;
			}
		}
		return number_still_dead;
	}

	public int sideCount(int side) {
		int scount = 0;
		for(int j = 0; j < number_of_columns; j++) {
			if(war[side][j] > -1) scount++;
		}
		return scount;
	}

	public void aftermathBattleCommonPartOne() {

		if(battletext > 0 && !checkForYourRowOrColumn("out_of_the_fight")) {
			masterStringOut("The battle is over!");
			Wait.longBlip(3);
		}

		//battlescars: what doesn't kill you makes you stronger. 
		for(int c = 0; c < 2; c++) {
			if(c != beast_fight) {
				for(int k = 0; k < number_of_columns; k++) {
					if(war[c][k] > -1) {
						army[war[c][k]].setpotential_wound(0);
						if(!army[war[c][k]].is_zombie() && army[war[c][k]].gethealth() > 0) {
							if(!out_of_the_fight[c][k]) army[war[c][k]].battlescar(scar[c][k] - army[war[c][k]].gethealth());
						}

						if(army[war[c][k]].getspecies().compareToIgnoreCase("cat") == 0) army[war[c][k]].endhigh_battle();
					}
				}
			}
		}
	}		

