	public void caveOfLives() {
		
		System.out.println("\n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n ***");
		masterStringOut("You are in complete darkness.");
		masterStringOut("Your every small movement and footstep makes a deep, long echo in this space.");
		masterStringOut("There is one other sound...");
		Wait.manySec(3);
		masterStringOut("\"Heh heh heh. Heh heh heh hmm. Hmm hmm hm.\"");
		Wait.manySec(3);
		masterStringOut("\nIt's faint, but it's there. Incessant laughter, low laughter, so low that it might be someone clearing their throat.");
		masterStringOut("Your eyes are adjusting- you are in a wide hallway. The walls rise into darkness- you can't see a ceiling- and the hall stretches forward into darkness too.");
		hitEnter(20997);
		
		int cave_position = 0;
		boolean user_remains_in_cave = true;
		boolean first_cave_screen = true;
		
		//make array of past lives
		ArrayList<Integer> past_lives = new ArrayList<Integer>();
		for(int pl = 1; pl < army[user].getgeneration(); pl++) {
			for(int gy = 0; gy < next_grave; gy++) {
				if(graveyard[gy].get_array_position() == user && graveyard[gy].getgeneration() == pl) past_lives.add(gy);
			}
		}
		

		do{
			String viewstring = "";
			if(!first_cave_screen) {
				viewstring += "\"Heh heh heh. Heh heh heh hmm. Hmm hmm hm.\"\n";
				System.out.println("\n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n \n\n\n\n\n");
			}
			int number_of_doors = 0;
			if(army[user].getgeneration() > 1){
				number_of_doors = 3;
				for(int d_minus = 3; d_minus > 0; d_minus--) {
					if((army[user].getgeneration() + -3 * cave_position - d_minus) <= 0) number_of_doors--;
				} 
				if(number_of_doors == 0) masterStringOut("\nThere are no doors here.");
				else viewstring += "\nAlong the wall";
				if(number_of_doors == 1) {
					viewstring += ", there is a door. It has a single vertical groove carved in it.";
					if(graveyard[past_lives.get(0)].life_was_reused()) viewstring += "\nThere is a diagonal smear of blood on the door.";
				}
				if(number_of_doors == 2) {
					viewstring += ", there are two doors. One door has a single vertical groove carved in it. The other door has two grooves.";
					if(graveyard[past_lives.get(1)].life_was_reused()) viewstring += "\nThere is a diagonal smear of blood on the door with two grooves.";
					if(graveyard[past_lives.get(0)].life_was_reused()) viewstring += "\nThere is a diagonal smear of blood on the door with one groove.";
				}
				if(number_of_doors == 3) {
					viewstring += ", there are three doors.";
					viewstring += "\nOne door has ";
					int nextdoor = army[user].getgeneration() - 1 + -3 * cave_position;
					viewstring += nextdoor+" vertical grooves carved in it.";
					if(graveyard[past_lives.get(nextdoor - 1)].life_was_reused()) viewstring += "\nThere is a diagonal smear of blood on the this door.";
					nextdoor--;
					viewstring += "\nThe next door has "+nextdoor+" grooves.";
					if(graveyard[past_lives.get(nextdoor - 1)].life_was_reused()) viewstring += "\nThere is a diagonal smear of blood on the this door.";
					nextdoor--;
					viewstring += "\nThe last door has ";
					if(nextdoor == 1) viewstring += "a single vertical groove carved in it.";
					else viewstring += nextdoor+" grooves.";
					if(graveyard[past_lives.get(nextdoor - 1)].life_was_reused()) viewstring += "\nThere is a diagonal smear of blood on this door.";
				}
				if(!first_cave_screen) viewstring += "\nThe hallway continues into darkness.";
				masterStringOut(viewstring);
			}
			first_cave_screen = false;
			
			String cave_choice = "null";
			boolean input_valid = false;
			do {
				if(number_of_doors == 1) masterStringOut("\n[  Door                                                          ]");
				if(number_of_doors == 2) masterStringOut("\n[  2                    1                                        ]");
				if(number_of_doors == 3) masterStringOut("\n[  "+(army[user].getgeneration() - 1 + -3 * cave_position)+"                    "+(army[user].getgeneration() - 2 + -3 * cave_position)+"                  "+(army[user].getgeneration() - 3 + -3 * cave_position)+"                     ]");
				masterStringOut("\n[      Go On                        Go Back                      ]");
				
				cave_choice = stringInput();

				if(cave_choice.compareToIgnoreCase("go on") == 0) {
					input_valid = true;
					cave_position++;
				}

				if(cave_choice.compareToIgnoreCase("go back") == 0) {
					input_valid = true;
					cave_position--;
				}
				
				if(cave_position < 0) {
					input_valid = true;
					
					masterStringOut("You find a wall that might be where you entered the cave. Your fingers search blindly for an opening.");
					Wait.manySec(2);
					masterStringOut("After a hopeless effort, dizziness overtakes you... You are drifting off to sleep...");
					Wait.manySec(2);
					hitEnter(21116);
				
					user_remains_in_cave = false;
					army[user].setround_clock(20);
					army[user].setxy(markers[0][8], markers[1][8]);
				}
				
				else {
					
					int life_to_try = -1;
										
					if(cave_choice.compareToIgnoreCase("door") == 0) {
						if(number_of_doors == 1) {
							life_to_try = past_lives.get(0); 
							input_valid = true;
						}
						else if(number_of_doors == 0) masterStringOut("There are no doors here.");
						else masterStringOut("Which door?");
					}

					if(cave_choice.compareToIgnoreCase(String.valueOf(army[user].getgeneration() - 1 + -3 * cave_position)) == 0 || cave_choice.compareToIgnoreCase(String.valueOf(army[user].getgeneration() - 2 + -3 * cave_position)) == 0 || cave_choice.compareToIgnoreCase(String.valueOf(army[user].getgeneration() - 3 + -3 * cave_position)) == 0) {
						life_to_try = past_lives.get(Integer.parseInt(cave_choice) - 1); 
						input_valid = true;
					}
					
					if(life_to_try > -1) {
						
						if(graveyard[life_to_try].life_was_reused()) masterStringOut("The door is locked.");
						else {
							
							input_valid = true;
							
							masterStringOut("The door opens.");
							Wait.manySec(2);
							masterStringOut("A figure stands in front you, with his back to you, nearly within arm's reach.");
							Wait.manySec(2);
							masterStringOut("He turns around and looks you in the eye. You were this person, once. You will be him again.");
							hitEnter(21190);

							// kill/bury player
							army[user].zero_health();
							for(int l = 0; l < armysize; l++) {
								army[l].setfriend(user, -1, turnclock, 21205);
								army[l].reset_zombie_meeting(user);
								army[l].reset_knows_joke(user, number_of_jokes);
								for(int p = 0; p < items.length; p++) {
									for(int q = 0; q < items[p].length; q++) {
										if(items[p][q].getowner() == user) {
											items[p][q].gets_dropped(markers[0][8], markers[1][8]);
										}
									}
								} 
							}	
							army[user].lose_all_meat();
							graveyard[next_grave] = army[user];
							next_grave++;
							
							// resurrect and return for encore
							army[user] = graveyard[life_to_try];
							army[user].return_for_encore();

							// put a dummy in the graveyard to fill the old place
							//constructor III
							graveyard[life_to_try] = new Human("j_doe", dice, 0, 1000, 0, humansize, armysize, boardside, false, 1);
							
							user_remains_in_cave = false;
							army[user].setxy(markers[0][8], markers[1][8]);
						}
					}
				}
			} while (!input_valid);


		}while(user_remains_in_cave);
	}




