	//Reference Toolkit
	
	public boolean confirmPosition(int soul, String place) {
		boolean confirmation = false;
		if(place.compareToIgnoreCase("plain")==0) {
			if(army[soul].getx() > 0 && army[soul].getx() <= boardside && army[soul].gety() > 0 && army[soul].gety() <= boardside) confirmation = true;
		}
		if(place.compareToIgnoreCase("forest")==0) {
			if(army[soul].getx() >= boardside + 3 && army[soul].getx() <= boardside + 8 && army[soul].gety() >= boardside + 3 && army[soul].gety() <= boardside + 8) confirmation = true;
		}
		return confirmation;
	}
	
	public int countUndead() {
		return countUndead("all");
	}
	
	public int countUndead(String which) {
		int z_count = 0;
		for(int i = 0; i < armysize; i++) {
			if(army[i].is_zombie() || army[i].has_symbol()) {
				boolean include = true;
				if(which.contains("buried") && army[i].how_buried() > 0) include = false;
				if(which.contains("active") && (army[i].how_buried() <= 0 || !army[i].is_zombie())) include = false;
				if(which.contains("here")) {
					int found_name_end = Math.min(which.indexOf("here") + 11, which.length()); 
					String found_name = which.substring(which.indexOf("here") + 5, found_name_end);
					if(getNumberFromPartName(found_name) != -1) {
						if(!samePlace(getNumberFromPartName(found_name), i)) include = false;
					}
					else include = false;
//					System.out.println("**** 19548 found_name is "+found_name+" found_name_end is "+found_name_end+" i is "+i+"; include is"+include+"; getnumber is "+getNumberFromPartName(found_name)+"; same place is "+samePlace(getNumberFromPartName(found_name), i));
				}
				if(which.contains("known")) {
					int found_name_end = Math.min(which.indexOf("known") + 12, which.length()); 
					String found_name = which.substring(which.indexOf("here") + 6, found_name_end);
					if(getNumberFromPartName(found_name) != -1) {
						if(!army[getNumberFromPartName(found_name)].knows_a_zombie(i)) include = false;
					}
					else include = false;
				}
				if(which.compareToIgnoreCase("all") == 0) include = true;
				
				if(include) z_count++;
																 
//				if(army[i].getaffiliation() != 0) masterStringOut("*** The Undead "+army[i].getname()+" is in gang "+army[i].getaffiliation()+"!");
				if(army[i].getx() == house_coord && army[i].gety() == house_coord) masterStringOut("*** The Undead "+army[i].getname()+" is in the longhouse!");

			}
		}
	
		return z_count;
	
	}
	
	public int findGrave(String deceased_name) {
		int gravesite = -1;
		for (int i = 0; i < user*100; i++) {
			if(graveyard[i].getname().compareTo(deceased_name) == 0) {
				gravesite = i;
				break;
			}
		}
		return gravesite;
	}
	
	public String getAlphabet(int alpha_index) {
		String alpha_out = "";
		if(alpha_index < 26) alpha_out = alphabet[alpha_index];
		else {
			int letter_to_repeat = (alpha_index + 1) % 26;
			if(letter_to_repeat == 0) letter_to_repeat = 26;
			letter_to_repeat--;
			int times_to_repeat = (int)Math.ceil((alpha_index + 1)/26.0);
			while(times_to_repeat > 0) {
				alpha_out += alphabet[letter_to_repeat];
				times_to_repeat--;
			}
		}
		return alpha_out;
	}
	
	public String getDirection(int x_here, int y_here, int x_there, int y_there) {
		String direction = "null";
		int x_diff = x_there - x_here;
		int y_diff = y_there - y_here;
		if(x_diff >= 1) {
			if(y_diff <= -1) direction = "North and East";
			if(y_diff >= 1) direction = "South and East";
			if(y_diff == 0) direction = "East";
		}
		if(x_diff <= -1) {
			if(y_diff <= -1) direction = "North and West";
			if(y_diff >= 1) direction = "South and West";
			if(y_diff == 0) direction = "West";
		}
		if(x_diff == 0) {
			if(y_diff <= -1) direction = "North";
			if(y_diff >= 1) direction = "South";
			if(y_diff == 0) direction = "close";
		}
		
		return direction;
	}
	
	public double getDistance(int player_one, int player_two) {
		if(player_one < armysize && player_two < armysize) return getDistance(army[player_one].getx(), army[player_two].gety(), army[player_one].getx(), army[player_two].gety());
		else return 0;
	}

	public double getDistance(int x_here, int y_here, int x_there, int y_there) {
		double distance = 0;
		int x_diff = x_there - x_here;
		int y_diff = y_there - y_here;
		distance = Math.sqrt(Math.pow(x_diff, 2) + Math.pow(y_diff, 2));
		return distance;
	}
	
	public String getForestDirectionString(int player_number) {
		//in this and the other methods below, we take into account the possibility that the user is at the forest door.
		String direction = "";
		if(army[player_number].ishere(forest_entry_x, forest_entry_y)) direction = forest_direction;
		else {
			boolean x_first = (dice.throwdice(1, 2) == 1) ? true : false;
			if(x_first) {
				if(forest_entry_x > army[player_number].getx()) direction = "East";
				else if(forest_entry_x < army[player_number].getx()) direction = "West";
				else if(forest_entry_y > army[player_number].gety()) direction = "South";
				else if(forest_entry_y < army[player_number].gety()) direction = "North";
			}
			else {
				if(forest_entry_y > army[player_number].gety()) direction = "South";
				else if(forest_entry_y < army[player_number].gety()) direction = "North";
				else if(forest_entry_x > army[player_number].getx()) direction = "East";
				else if(forest_entry_x < army[player_number].getx()) direction = "West";
			}
		}
		return direction;
	}
	
