	public int incantationWasSpoken(String words) {
		boolean any_words = false;
		int word_a_spoken = -1;
		int word_b_spoken = -1;
		int word_c_spoken = -1;
		if(army[user].getincantation(0) != -1) {
			String[] word = words.split(" ");
			for(int i = 0; i < word.length; i++) {
				if(word_b_spoken != -1 && word_c_spoken == -1) {
					if(word[i].compareToIgnoreCase(incantations[army[user].getincantation(2)]) == 0 && i == word_b_spoken + 1) {
						word_c_spoken = i;
						any_words = true;
						break;
					}
					else {
						word_b_spoken = -1;
						word_a_spoken = -1;
					}
				} 
				if(word_a_spoken != -1 && word_b_spoken == -1) {
					if(word[i].compareToIgnoreCase(incantations[army[user].getincantation(1)]) == 0 && i == word_a_spoken + 1) {
						word_b_spoken = i;
						any_words = true;
					}
					else word_a_spoken = -1;
				}
				if(word[i].compareToIgnoreCase(incantations[army[user].getincantation(0)]) == 0) {
					word_a_spoken = i;
					any_words = true;
				}
			}
		}
		int to_return = -1;
		if(any_words) to_return = 1;
		if(word_c_spoken != -1) to_return = 0;
		return to_return; 
	}
	
	public boolean nameMatchup(int line, String s1, String s2) {
	
		//s1 is the user input, or the string that is potentially partial. s2 should be the exact name.

		//first, we must check to see if the user knows someone with this exact name. We are trying to avoid the "Ben/Bendix" phenomenon: if the user knows both and 
		//types "Ben," the input will be matched to Bendix, since he precedes Ben in the army array. So first we want to check to see if the input is an exact match 
		//with someone who is present and whom the user knows the name of; if this is not the person in question, the method will return FALSE.
		
//		System.out.println("**** 20502 will attempt match "+s1+" "+s2);

		boolean matchup = false;
		boolean decision_is_made = false;
		
		if(s1.compareToIgnoreCase(s2) == 0) {
			matchup = true;
			decision_is_made = true;
		}
		if(!decision_is_made) {
else_loop:	for(int i = 0; i < armysize; i++) {
				if(army[user].getfriend(i) > -1 && samePlace(user, i)) {
					if(army[i].getspecies().compareToIgnoreCase("human") == 0) {
						if(s1.compareToIgnoreCase(army[i].getname()) == 0) {
							matchup = false;
							decision_is_made = true;
						}
					}
					else if(army[i].has_name()) {
						if(s1.compareToIgnoreCase(army[i].getname()) == 0) {
							matchup = false;
							decision_is_made = true;
						}
					}
					if(decision_is_made) break else_loop;
				}
			}
		}
		if(!decision_is_made) {
//			System.out.println("**** 20531 made it here "+s1+" "+s2);

			//if the name, without the number, is fewer than 6 characters, we use that as the length we are matching. Otherwise, we use just six characters.
		
			int searchlength = 6;
			s1 = s1.trim();
			s2 = s2.trim();
		
			String[] s1break = s1.split (" ");
			String[] s2break = s2.split (" ");
		
			if (s1break[0].length() < searchlength) searchlength = s1break[0].length();
			if (s2break[0].length() < searchlength) searchlength = s2break[0].length();

		
			//if either string is only one character, the other string must also be one character for the match to be true.
			if (s1break[0].length() > 1 && s2break[0].length() > 1) {
				String s1short = s1break[0].substring(0, searchlength);
				String s2short = s2break[0].substring(0, searchlength);
//				System.out.println("**** 20547 s1, s2 shorts are "+s1short+" "+s2short);
				if(s1short.compareToIgnoreCase(s2short) == 0) {
					matchup = true;
					//if(matchup) System.out.println("**** 19490 round four matched. s1 is "+s1+", s2 is "+s2+". line of call is "+line);
				}
			}
		}
		
		return matchup;
	}
	
	public int numberInGang(int member) {
		int this_gang = army[member].getaffiliation();
		int number_to_return = 0;
		for(int i = 0; i < humansize; i++) {
			if(this_gang != 0 && army[i].getaffiliation() == this_gang) number_to_return++;
		}
		return number_to_return;
	}
	
	public boolean menuMatchup(String s1, String s2) {
	
		boolean matchup = false;
		
		if(s1.compareToIgnoreCase(s2) == 0) matchup = true;
		else {
			int searchlength = 6;
		
			String[] s1break = s1.split (" ");
			String[] s2break = s2.split (" ");
		
			if (s1break[0].length() < searchlength) searchlength = s1break[0].length();
			if (s2break[0].length() < searchlength) searchlength = s2break[0].length();
			
			if(searchlength > 0) {
				
				String s1short = s1break[0].substring(0, searchlength);
				String s2short = s2break[0].substring(0, searchlength);
		
				if(s1short.compareToIgnoreCase(s2short) == 0) matchup = true;
			}
		}
		
		return matchup;
	}
	
	public boolean oldFriendCheck(int player1, int player2) {
		boolean pals = false;
main:	do {
			if(sameGang(player1, player2)) break main;
			if(army[player1].getaffiliation() == 0 && army[player1].getformer_affiliation(0) == 0) break main;
			if(army[player2].getaffiliation() == 0 && army[player2].getformer_affiliation(0) == 0) break main;
			int i_limit = 100;
			int j_limit = 100;
i_loop: 	for(int i = -1; i < i_limit; i++) {
j_loop:			for(int j = -1; j < j_limit; j++) {
					int p_one = -23;
					int p_two = -24;
					if(i == -1) p_one = army[player1].getaffiliation(); 
					else {
						if(army[player1].getformer_affiliation(i) == 0) break i_loop;
						else p_one = army[player1].getformer_affiliation(i);
					}
					if(j == -1) p_two = army[player2].getaffiliation(); 
					else {
						if(army[player2].getformer_affiliation(j) == 0) break j_loop;
						else p_two = army[player2].getformer_affiliation(j);
					}
					if(p_one != 0 && p_two != 0 && p_one == p_two) {
						pals = true;
						break main;
					}
					if(j == j_limit - 1) j_limit++;
				}
				if(i == i_limit - 1) i_limit++;
			}
		} while (0 == 1);

		return pals;
	}
	
