	public void whereIsHe(int target) {
		
		double distance = 0;
		String direction = "null";
		if(army[target].getx() > 0) {
			direction = getDirection(markers[0][0], markers[1][0], army[target].getx(), army[target].gety());
			distance = getDistance(markers[0][0], markers[1][0], army[target].getx(), army[target].gety());
		}
		else {
			direction = getDirection(markers[0][0], markers[1][0], army[target].getlast_x(), army[target].getlast_y());
			distance = getDistance(markers[0][0], markers[1][0], army[target].getlast_x(), army[target].getlast_y());
		}
		
		if(distance < 1.5) masterStringOut("GREGOR:  \"Believe it or not, he's very close by.\""); 
		else {
			String distmessage = "GREGOR:  \"He said he was heading "+direction+" of here.";
			if(distance > 10) distmessage = distmessage + " He's a ways out by now, though, I'm afraid.";
			distmessage = distmessage + "\"";
			masterStringOut(distmessage);
		} 
	
	}

	
	//Interface Toolkit

	public String addArticle(String noun, boolean upper) {
		String nounlow = noun.toLowerCase();
		String article = "A";
		if(nounlow.indexOf("a") == 0 || nounlow.indexOf("e") == 0 || nounlow.indexOf("i") == 0 || nounlow.indexOf("o") == 0) article = "An";
		if(!upper) article = article.toLowerCase();
		return article;
	}	

	public String capitalFirst(String phrase) {
		String cap = phrase.substring(0,1).toUpperCase() + phrase.substring(1);
		return cap;
	}
	
	public String getPluralForm(String singular) {
		String plural = "";
		if(singular.compareToIgnoreCase("butterfly") == 0) plural = "butterflies";
		if(singular.compareToIgnoreCase("creeper") == 0) plural = "creepers";
		if(singular.compareToIgnoreCase("devil") == 0) plural = "devils";
		if(singular.compareToIgnoreCase("gnome") == 0) plural = "gnomes";
		if(singular.compareToIgnoreCase("pig") == 0) plural = "pigs";
		if(singular.compareToIgnoreCase("rat") == 0) plural = "rats";
		if(singular.compareToIgnoreCase("rattish man") == 0) plural = "rattish men";
		if(singular.compareToIgnoreCase("skeleton") == 0) plural = "skeletons";
		if(singular.compareToIgnoreCase("snake") == 0) plural = "snakes";
		if(singular.compareToIgnoreCase("spider") == 0) plural = "spiders";
		if(singular.compareToIgnoreCase("tree") == 0) plural = "trees";
		
		return plural;
		
	}
	
