	public void longStringOut(String longstring) {
	
		int screen_width = 80;
		
		if(longstring.length() < screen_width) System.out.println(longstring);
		
		else {
			String[] longstring_chopped = longstring.split(" ");

			if(longstring_chopped.length < 1) {
				longstring_chopped = new String[1];
				longstring_chopped[0] = longstring;
			}
			
			String testline = longstring_chopped[0] + " ";
		
			for(int i = 1; i < longstring_chopped.length; i++) {
				if(testline.length() + longstring_chopped[i].length() > screen_width) {
					masterStringOut(testline);
					testline = ""; 
				}
				testline = testline + longstring_chopped[i];
				if(testline.length() != 80) testline = testline +  " ";
				if(i == longstring_chopped.length - 1) System.out.println(testline); 
			}
		}
	}
	
