	public void resetStatKnowledge(int subject) {
		//strength   : 0
		//health     : 1
		//max health : 2
		//speed      : 3
		//skill      : 4
		//personality: 5
		//morale     : 6
		if(subject == user) {
			statUncertainty[user][4] = 0;
			statUncertainty[user][5] = 0;
			statUncertainty[user][6] = 0;
			statUncertainty[user][0] = 100;
			statUncertainty[user][1] = 100;
			statUncertainty[user][2] = 100;
			statUncertainty[user][3] = 100;
		}
		else {
			for(int i = 0; i < 7; i++) {
				statUncertainty[subject][i] = 100 - (int)army[user].getage()/2;
			}
		}
		
		updateStatKnowledge(subject, "reset");
		
	}
	
