	public void statDisplay(int subject, String display_type) {
		//strength   : 0
		//health     : 1
		//max health : 2
		//speed      : 3
		//skill      : 4
		//personality: 5
		//morale     : 6
		
		//quick update of stats...
		for(int statdis = 0; statdis < 7; statdis++) {
			if(statUncertainty[subject][statdis] == 0) {
				Integer quick_update = army[subject].getstat_for_uncertainty(statdis);
				statKnowledge[subject][statdis] = quick_update.toString();
				if(statdis == 1 && statUncertainty[subject][2] != 0) updateStatKnowledge(subject, "quick max health");
				if(statdis == 2 && statUncertainty[subject][1] != 0) updateStatKnowledge(subject, "quick health");
			}
		}
		 	
		String reportstring = "~~";
		if(army[user].getfriend(subject) > -1) reportstring += army[subject].getname();
		else reportstring += "stranger";
		if(army[subject].is_zombie()) {
			reportstring = reportstring + " (UNDEAD)";
		}
		
		if(display_type.compareToIgnoreCase("long") == 0) reportstring += "       ";
		else reportstring += "\n";
		
		reportstring += "Strength: "+statKnowledge[subject][0]+" Health: "+statKnowledge[subject][1]+"(Max "+statKnowledge[subject][2]+") Speed: "+statKnowledge[subject][3];
		
		if(display_type.compareToIgnoreCase("long") == 0) reportstring += " \n          ";
		else reportstring += "\n ";
		
		reportstring += "Skill: "+statKnowledge[subject][4]+" Personality: "+statKnowledge[subject][5]+" Morale: "+statKnowledge[subject][6];
		
		masterStringOut(reportstring);
		
	}
	
