	public String stringInput() {

 		//  open up standard input
    	// BufferedReader is the class, br is the object, instantiated here. 
   		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

  	   	String user_arg = "null";

    	//  read the user input from the command-line; need to use try/catch with the 
    	//  readLine() method 
    	try { 
    		user_arg = br.readLine(); 
    	} 
    	catch (IOException ioe) { 
    		masterStringOut("IO error trying to read your input!"); 
    		System.exit(1); 
    	}
		
		user_arg = user_arg.trim();
		
		return user_arg;
    }
	
	public String stringMenuChoice(String[] string_array) {
		String menu_choice = "";
		boolean exit_loop = false;
		do {
			menu_choice = stringInput();
			for(int i = 0; i < string_array.length; i++) {
				if(menu_choice.compareToIgnoreCase(string_array[i]) == 0) {
					exit_loop = true;
					break;
				}
			}
		} while (!exit_loop);
		return menu_choice;
	}

	public int stringMenuChoiceInt(String[] string_array) {
		int return_value = -1;
		String menu_choice = "";
		boolean exit_loop = false;
		do {
			menu_choice = stringInput();
			for(int i = 0; i < string_array.length; i++) {
				if(menu_choice.compareToIgnoreCase(string_array[i]) == 0) {
					return_value = i;
					exit_loop = true;
					break;
				}
			}
		} while (!exit_loop);
		return return_value;
	}

	public void updateStatKnowledge(int subject, String event) {
		//strength   : 0
		//health     : 1
		//max health : 2
		//speed      : 3
		//skill      : 4
		//personality: 5
		//morale     : 6
		int[] statMargins = new int[7];
		for(int sm = 0; sm < 7; sm++) {
			statMargins[sm] = 0;
		}
		
		if(event.compareToIgnoreCase("duel round experienced") == 0) {
			statUncertainty[subject][3] += -1*(10 + (int)(army[user].getage()/5));
			statMargins[3] = 4;
			if(subject != user) {
				statUncertainty[subject][4] += -1*(20 + (int)(army[user].getage()*2/5));
				statUncertainty[subject][6] += -1*(15 + (int)(army[user].getage()*2/5));
				statMargins[4] = 50;
				statMargins[6] = 20;
			}		
		}
		if(event.compareToIgnoreCase("duel round seen") == 0) {
			statUncertainty[subject][3] += -1*(5 + (int)(army[user].getage()/5));
			statMargins[3] = 4;
			if(subject != user) {
				statUncertainty[subject][4] += -1*(8 + (int)(army[user].getage()*2/5));
				statUncertainty[subject][6] += -1*(12 + (int)(army[user].getage()*2/5));
				statMargins[4] = 50;
				statMargins[6] = 20;
			}		
		}
		if(event.compareToIgnoreCase("duel hit experienced") == 0) {
			statUncertainty[subject][0] += -1*(20 + (int)(army[user].getage()/10));
			statUncertainty[subject][1] += -20;
			statMargins[0] = 8;
			statMargins[1] = 25;
			if(subject != user) statUncertainty[subject][1] += -1*(int)(army[user].getage()/20);
			else {
				statUncertainty[subject][2] += -15;
				statMargins[2] = 25;
			}
		}
		if(event.compareToIgnoreCase("duel hit seen") == 0) {
			statUncertainty[subject][0] += -1*(5 + (int)(army[user].getage()/10));
			statUncertainty[subject][1] += -1*(12 + (int)(army[user].getage()/20));
			statMargins[0] = 8;
			statMargins[1] = 25;
		}
		if(event.compareToIgnoreCase("battle round experienced") == 0) {
			statUncertainty[subject][3] += -1*(6 + (int)(army[user].getage()/5));
			statMargins[3] = 4;
			if(subject != user) {
				statUncertainty[subject][4] += -1*(12 + (int)(army[user].getage()*2/5));
				statUncertainty[subject][6] += -1*(9 + (int)(army[user].getage()*2/5));
				statMargins[4] = 50;
				statMargins[6] = 20;
			}		
		}
		if(event.compareToIgnoreCase("battle round seen") == 0) {
			statUncertainty[subject][3] += -1*(3 + (int)(army[user].getage()/5));
			statMargins[3] = 4;
			if(subject != user) {
				statUncertainty[subject][4] += -1*(5 + (int)(army[user].getage()*2/5));
				statUncertainty[subject][6] += -1*(7 + (int)(army[user].getage()*2/5));
				statMargins[4] = 50;
				statMargins[6] = 20;			
			}		
		}
		if(event.compareToIgnoreCase("battle hit experienced") == 0) {
			statUncertainty[subject][0] += -1*(12 + (int)(army[user].getage()/10));
			statUncertainty[subject][1] += -12;
			statMargins[0] = 8;
			statMargins[1] = 25;
			if(subject != user) statUncertainty[subject][1] += -1*(int)(army[user].getage()/20);
			else {
				statUncertainty[subject][2] += -9;
				statMargins[2] = 25;
			}
		}
		if(event.compareToIgnoreCase("battle hit seen") == 0) {
			statUncertainty[subject][0] += -1*(3 + (int)(army[user].getage()/10));
			statUncertainty[subject][1] += -1*(7 + (int)(army[user].getage()/20));
			statMargins[0] = 8;
			statMargins[1] = 25;
		}
		if(event.compareToIgnoreCase("turn change") == 0) {
			if(subject != user && sameGang(subject, user)) {
				statUncertainty[subject][2] += -4;
				statMargins[2] = 25;
			}
		}
		if(event.compareToIgnoreCase("recovery") == 0) {
			if(subject == user) {
				statUncertainty[subject][1] += -20;
				statUncertainty[subject][2] += -15;				
				statMargins[1] = 25;
				statMargins[2] = 25;
			}
		}
		if(event.compareToIgnoreCase("train") == 0) {
			statUncertainty[subject][4] = 0;
			statMargins[4] = 50;
		}
		if(event.compareToIgnoreCase("encounter") == 0) {
			if(subject != user) {
				statUncertainty[subject][5] += -1*(30 + (int)(army[user].getage()*.3));
				statUncertainty[subject][6] += -1*(15 + (int)(army[user].getage()*.4));				
				statMargins[5] = 50;
				statMargins[6] = 20;
			}
		}
		
		if(event.compareToIgnoreCase("reset") == 0) {
			statMargins[4] = 50;
			statMargins[6] = 20;
			statMargins[3] = 4;
			statMargins[0] = 8;
			statMargins[1] = 25;
			statMargins[2] = 25;
			statMargins[5] = 50;
		}


		//strength   : 0
		//health     : 1
		//max health : 2
		//speed      : 3
		//skill      : 4
		//personality: 5
		//morale     : 6
	
		for(int i = 0; i < 7; i++) {
			if(event.compareToIgnoreCase("quick health") == 0 && i != 1) continue;
			if(event.compareToIgnoreCase("quick max health") == 0 && i != 2) continue;
			if(statMargins[i] > 0) {
				if(statUncertainty[subject][i] < 0) statUncertainty[subject][i] = 0;
						
				if (statUncertainty[subject][i] >= 95) statKnowledge[subject][i] = "???";
				else {
					int dice_result = (2*dice.throwdice(1,2) - 3);
					float statErrorFloat = (statUncertainty[subject][i] * statMargins[i] * dice_result)/100;
					int statError = (int)(statErrorFloat);
//					masterStringOut("statError = "+statError+"; subject is "+army[subject].getname()+" ("+subject+")");
//					masterStringOut("(uncertainty = "+statUncertainty[subject][i]+"; base margin = "+statMargins[i]+")");
//					masterStringOut("statErrorFloat = "+statErrorFloat+"    dice result = "+dice_result);
					Integer new_knowledge =  army[subject].getstat_for_uncertainty(i) + statError;
					if(i == 0 && new_knowledge < 1) new_knowledge = 1;
					if(i == 1) {
						if(new_knowledge <= 0 && army[subject].gethealth() > 0) new_knowledge = 1;
						String[] get_real_stat = statKnowledge[subject][2].split(" ");
						if(!get_real_stat[0].contains("?")) { 
							if(new_knowledge > Integer.valueOf(get_real_stat[0])) new_knowledge = Integer.valueOf(get_real_stat[0]);
						}
					}					
					if(i == 2) {
						if(new_knowledge <= 0) new_knowledge = 1;
						String[] get_real_stat = statKnowledge[subject][1].split(" ");
						if(!get_real_stat[0].contains("?")) { 
							if(new_knowledge < Integer.valueOf(get_real_stat[0])) new_knowledge = Integer.valueOf(get_real_stat[0]);
						}
					}
					if(i >= 3 && i <= 6 && new_knowledge < 1) new_knowledge = 1;
					if(i == 5 && new_knowledge > 100) new_knowledge = 100;
					if(i == 6 && new_knowledge > 40) new_knowledge = 40;
					statKnowledge[subject][i] =  new_knowledge.toString();
					if(statUncertainty[subject][i] > 80) statKnowledge[subject][i] += " (???)";
					else if(statUncertainty[subject][i] > 50) statKnowledge[subject][i] += " (??)";
					else if(statUncertainty[subject][i] > 5) statKnowledge[subject][i] += " (?)";
				} 
			}
		
		}
		
	}
		
