	// Forest Events + Tools

	public boolean chantIsOn(int gang_number) {
		//the first necessary condition is whether this gang is already chanting. Then make sure they're not in the forest (there should be no chanting if they 
		//are in the forest, but make sure.) Then we check for morale and total party evaluation, and possibly turn the chant off.
		//finally, we return a boolean value reporting whether the chant is happening.
		boolean it_is_on = false;
		int party_evaluation = 0;
		int count_for_average = 0;
		int total_for_average = 0;
		if(chanting_gangs.contains(new Integer(gang_number))) {
			it_is_on = true;
chant_loop:	for(int i = 0; i < humansize; i++) {
				if(army[i].getaffiliation() == gang_number) {
					if(army[i].gethealth() > 0) {
						if(!army[i].in_the_forest()) {
							party_evaluation += army[i].getevaluation();
							total_for_average += army[i].getmorale();
							count_for_average++;
						}
						else {
							it_is_on = false;
							party_evaluation = 0;
							break chant_loop;
						}
					}
				}
			}
			if(party_evaluation != 0 && (party_evaluation < 100 || total_for_average/count_for_average < 32)) {
				it_is_on = false;
				if(army[user].getaffiliation() == gang_number) masterStringOut("The mood in the gang has changed... no one seems so keen on the forest now.");
			}
			if(!it_is_on) chanting_gangs.remove(new Integer(gang_number));
		}
		
		return it_is_on;
	}

	public boolean chantIsOn(int gang_number, String tag) {
	//if the tag is "on," we will return true only if we are turning it on right now. So first, we check to see if the gang is already chanting. If NOT, we
		//then check if they're in the forest; if NOT, we check the time that's gone by is sufficiently long. If so, we check for morale and total party evaluation. 
		//If that too is sufficient, we turn the chant ON, and then and 
		//only then will we return TRUE.
		boolean it_is_on = false;
		int party_evaluation = 0;
		int count_for_morale_average = 0;
		int total_for_morale_average = 0;
		int count_for_clock_average = 0;
		int total_for_clock_average = 0;
		
		if(!chanting_gangs.contains(new Integer(gang_number))) {
chant_loop:	for(int i = 0; i < humansize; i++) {
				if(army[i].getaffiliation() == gang_number) {
					if(army[i].gethealth() > 0) {
						if(!army[i].in_the_forest()) {
							if(army[i].getforest_entry_clock() > 40) {
								party_evaluation += army[i].getevaluation();
								total_for_morale_average += army[i].getmorale();
								count_for_morale_average++;
							}
							total_for_clock_average += army[i].getforest_entry_clock();
							count_for_clock_average++;
						}
						else {
							it_is_on = false;
							party_evaluation = 0;
							break chant_loop;
						}
					}
				}
			}
			if(count_for_morale_average > 0 && count_for_clock_average > 0) {
				if(party_evaluation >= 100 && total_for_morale_average/count_for_morale_average > 34 && total_for_clock_average/count_for_clock_average > 40) it_is_on = true;
			}
		}
		
		if(count_for_morale_average > 0 && count_for_clock_average > 0) {
//			System.out.println("**** 20354 party_evaluation: "+party_evaluation+"    morale average: "+total_for_morale_average/count_for_morale_average+"  clock average: "+total_for_clock_average/count_for_clock_average+"   it_is_on is "+it_is_on);
			//hitEnter(20355);
			if(total_for_clock_average/count_for_clock_average < 15) {
				it_is_on = false;
				chantFail(gang_number);
			}
		}

		if(it_is_on) {
			chanting_gangs.add(gang_number);
//			System.out.println("****20319 chanting gang: #"+gang_number);
//			hitEnter(20320);
		}
		
		return it_is_on;
	}

	public void chantFail(int gang_number) {
		boolean user_is_here_for_fail = false;
		int count_for_message = 0;
		//lowers morale, turns off chant.
chant_loop:	for(int i = 0; i < humansize; i++) {
			if(army[i].getaffiliation() == gang_number) {
				if(army[i].gethealth() > 0) {
					army[i].setmorale(20);
					if(i == user) user_is_here_for_fail = true;
					count_for_message++;
				}
			}
		}
		if(user_is_here_for_fail && count_for_message > 2) masterStringOut("A hush falls over the gang..."); 
		if(chanting_gangs.contains(new Integer(gang_number))) chanting_gangs.remove(new Integer(gang_number));
	}

	public int[] enterForestSolo(int poor_soul) {
		boolean[][] forest_perceived = new boolean[6][6];
		forest_perceived = forest();
		army[poor_soul].setforest_entry_clock(0);
		int entry_point_x = 0;
		int entry_point_y = 0;
		int exit_point_x = 0;
		int exit_point_y = 0;
		do {
			entry_point_x = dice.throwdice(1, 6) - 1;
			entry_point_y = dice.throwdice(1, 6) - 1;
		} while (!forest_perceived[entry_point_x][entry_point_y]);
		do {
			exit_point_x = dice.throwdice(1, 6) - 1;
			exit_point_y = dice.throwdice(1, 6) - 1;
		} while (!forest_perceived[exit_point_x][exit_point_y] || (entry_point_x == exit_point_x && entry_point_y == exit_point_y));
		army[poor_soul].perceive_forest_anew(forest_perceived, entry_point_x, entry_point_y, exit_point_x, exit_point_y);
		if(poor_soul == user) resetKnownForest();
		int[] entry = new int[2];
		entry[0] = entry_point_x;
		entry[1] = entry_point_y;		
		return entry;
	}	

	public boolean checkAndCorrectInTheForest(int j) {
		if(army[j].in_the_forest()) {
			if(army[j].getx() < boardside + 3 || army[j].getx() > boardside + 8 || army[j].gety() < boardside + 3 || army[j].gety() > boardside + 8) army[j].complete_leaving_forest();
		}
		else {
			if(army[j].getx() >= boardside + 3 && army[j].getx() <= boardside + 8 && army[j].gety() >= boardside + 3 && army[j].gety() <= boardside + 8) army[j].set_in_the_forest_true();
		}  
		return army[j].in_the_forest();
	}
	
	public int[] forestNonuserMakesForTheExit(int j) {
		
		int x_flip = 0;
		int y_flip = 0;
		
		//if the player is next to the forest exit, the player will exit- otherwise, the player will randomly try a direction that is possible.
		if(army[j].getx() == army[j].getforest_exit_perceived_x() + boardside + 3 && army[user].gety() + 1 == army[user].getforest_exit_perceived_y() + boardside + 3) {
			x_flip = 0;
			y_flip = 1;
		}
		else if(army[j].getx() == army[j].getforest_exit_perceived_x() + boardside + 3 && army[user].gety() - 1 == army[user].getforest_exit_perceived_y() + boardside + 3) {
			x_flip = 0;
			y_flip = -1;
		}
		else if(army[j].getx() + 1 == army[j].getforest_exit_perceived_x() + boardside + 3 && army[user].gety() == army[user].getforest_exit_perceived_y() + boardside + 3) {
			x_flip = 1;
			y_flip = 0;
		}
		else if(army[j].getx() - 1 == army[j].getforest_exit_perceived_x() + boardside + 3 && army[user].gety() == army[user].getforest_exit_perceived_y() + boardside + 3) {
			x_flip = -1;
			y_flip = 0;
		}
		else if(army[j].getbird_report().length() > 0) {
			if(army[j].getbird_report().substring(0,1).compareToIgnoreCase("N") == 0) {
				x_flip = 0;
				y_flip = -1;
			}
			if(army[j].getbird_report().substring(0,1).compareToIgnoreCase("S") == 0) {
				x_flip = 0;
				y_flip = 1;
			}
			if(army[j].getbird_report().substring(0,1).compareToIgnoreCase("W") == 0) {
				x_flip = -1;
				y_flip = 0;
			}
			if(army[j].getbird_report().substring(0,1).compareToIgnoreCase("E") == 0) {
				x_flip = 1;
				y_flip = 0;
			}
			army[j].setbird_report(army[j].getbird_report().substring(1));
		}
		
		else {
			boolean dir_possible = false;
			int dir_counter = 0;
			do {
				x_flip = 0;
				y_flip = 0;
				int move_choice = dice.throwdice(1, 4);
				if(move_choice == 1) x_flip = 1;
				if(move_choice == 2) x_flip = -1;
				if(move_choice == 3) y_flip = 1;
				if(move_choice == 4) y_flip = -1;											
				if(army[j].getforest_perceived(army[j].getx() + x_flip - boardside - 3, army[j].gety() + y_flip - boardside - 3)) dir_possible = true;
				dir_counter++;
				if(dir_counter > 100) {
					System.out.println("*** Stuck at 20374 player is "+j+" at "+army[j].getx()+" "+army[j].gety()+" move_choice = "+move_choice+" x_flip = "+x_flip+" y_flip = "+y_flip+" boardside = "+boardside);
					for(int ij = 0; ij < 6; ij++) {
						String forest_line = "|";
						for(int jj = 0; jj < 6; jj++) {
							if(army[j].getforest_exit_perceived_x() == jj && army[j].getforest_exit_perceived_y() == ij) forest_line = forest_line + "O";
							else if(army[j].getx() - boardside - 3 == jj && army[j].gety() - boardside - 3 == ij) forest_line = forest_line + "*";
							else {
								if(army[j].getforest_perceived(jj, ij)) forest_line = forest_line + "^";
								else forest_line = forest_line + " ";
							}
						}
						masterStringOut(forest_line);
					}
					hitEnter(20567);
				}
			} while(!dir_possible);
		}
		
		int[] dir_changes = new int[2];
		dir_changes[0] = x_flip;
		dir_changes[1] = y_flip;
		return dir_changes;
	}
	
	public void enterForest(int poor_soul) {
	
		//this method creates a perception of the 6x6 forest, including an entrance and an exit. It then implants that perception into the poor soul's head and those of his gangfellows.	
		boolean[][] forest_perceived = new boolean[6][6];
		forest_perceived = forest();
		army[poor_soul].setforest_entry_clock(0);
		int entry_point_x = 0;
		int entry_point_y = 0;
		int exit_point_x = 0;
		int exit_point_y = 0;
		do {
			entry_point_x = dice.throwdice(1, 6) - 1;
			entry_point_y = dice.throwdice(1, 6) - 1;
		} while (!forest_perceived[entry_point_x][entry_point_y]);
		do {
			exit_point_x = dice.throwdice(1, 6) - 1;
			exit_point_y = dice.throwdice(1, 6) - 1;
		} while (!forest_perceived[exit_point_x][exit_point_y] || (entry_point_x == exit_point_x && entry_point_y == exit_point_y));
		army[poor_soul].perceive_forest_anew(forest_perceived, entry_point_x, entry_point_y, exit_point_x, exit_point_y);
		if(poor_soul == user) resetKnownForest();
		for(int i = 0; i < armysize; i++) {
			if(i != poor_soul && sameGang(i, poor_soul)) {
				army[i].perceive_forest_anew(forest_perceived, entry_point_x, entry_point_y, exit_point_x, exit_point_y);
				if(i == user) resetKnownForest();
			}
		}
		
	}
	
	public void exitForest(int lucky_soul) {
		for(int i = 0; i < armysize; i++) {
			if(sameGang(i, lucky_soul) && i != lucky_soul) army[i].leave_forest();
		}
		army[lucky_soul].leave_forest();
	} 

	public void resetKnownForest() {
		for(int i = 0; i < 6; i++) {
			for(int j = 0; j < 6; j++) {
				forest_map_found[i][j] = false;
			}
		}
	}

	public boolean[][] forest() {
	
		boolean[][] forest = new boolean[6][6];
		boolean[][] forest_wet = new boolean[6][6];
		int stream_start_x;
		int stream_start_y;
		boolean start_okay;
				
		for(int i = 0; i < 6; i++) {
			for(int j = 0; j < 6; j++) {
				forest[i][j] = true;
				forest_wet[i][j] = false;
			}
		}
		for(int i = 0; i < 3; i++) {
			int piece_start_x = dice.throwdice(1, 6) - 1;
			int piece_start_y = dice.throwdice(1, 6) - 1;
			for(int j = 0; j < 4; j++) {
				if(piece_start_x >= 0 && piece_start_x <= 5 && piece_start_y >= 0 && piece_start_y <= 5) forest[piece_start_x][piece_start_y] = false;
				piece_start_x = piece_start_x + dice.throwdice(1, 3) - 2;
				piece_start_y = piece_start_y + dice.throwdice(1, 3) - 2;
			}
		}
		
		do {
			stream_start_x = dice.throwdice(1,6) - 1;
			stream_start_y = dice.throwdice(1,6) - 1;
			start_okay = false;
			if( stream_start_x-1 >= 0 ) {
				if(forest[stream_start_x-1][stream_start_y]) start_okay = true;
			}
			if( stream_start_x+1 <= 5) {
				if(forest[stream_start_x+1][stream_start_y]) start_okay = true;
			}
			if( stream_start_y-1 >= 0) {
				if(forest[stream_start_x][stream_start_y-1]) start_okay = true;
			}
			if( stream_start_y+1 <= 5) {
				if(forest[stream_start_x][stream_start_y+1]) start_okay = true;
			}
		
			if(!forest[stream_start_x][stream_start_y]) start_okay = false;
		
		} while (!start_okay);
		
		forest_wet[stream_start_x][stream_start_y] = true;
		
		for(int w = 0; w < 20; w++) {
			for(int i = 0; i < 6; i++) {
				for(int j = 0; j < 6; j++) {
					if (forest[i][j] && forest_wet[i][j]) {
						if( i-1 >= 0 ) {
							if(forest[i-1][j]) forest_wet[i-1][j] = true;
						}
						if( i+1 <= 5) {
							if(forest[i+1][j]) forest_wet[i+1][j] = true;
						}
						if( j-1 >= 0) {
							if(forest[i][j-1]) forest_wet[i][j-1] = true;
						}
						if( j+1 <= 5) {
							if(forest[i][j+1]) forest_wet[i][j+1] = true;
						}
					}
				}
			}
		}
		
		return forest_wet;	
	}
	
	public void bluebirdEncounter(int target){
		//textlevel
		int bbtext = 0;
		if(army[user].getx() == army[target].getx() && army[user].gety() == army[target].gety()) bbtext = 1;
		if(sameGang(user, target)) bbtext = 2;
		if(user == target) bbtext = 3;
		
		//find the shortest path to the exit. We will test every possibility and find the shortest one.
		//how do we make an efficient tree... an array... each slot is a route... each slot contains an array... each slot in this is a direction... 
		//each direction is a letter... 
		//the bird has a limit... if it's more than 15 paces to the exit, which would be very rare, the bird will not help...
		//or it could be a flow control exercise... each turn of the gears makes another  

		boolean still_working = true;
		int[] best_route = new int[15];
		int[] trial_route = new int[15];
		int[] dummy_route = new int[15];
		int[] next_x = new int[15];
		int[] next_y = new int[15];
		for(int w = 0; w < 15; w++) {
			best_route[w] = -1;
			trial_route[w] = 0;
			dummy_route[w] = 0;
			next_x[w] = 0;
			next_y[w] = 0;
		}
		int x = army[target].getx() - boardside - 3;
		int y = army[target].gety() - boardside - 3;
		next_x[0] = x;
		next_y[0] = y;
		int i_step_limit = 14;

		int i = -1;
		
		pathfind: do {
			i++;
			boolean step_okay = true;			
			//N = 0, W = 1, S = 2, E = 3
			if(trial_route[i] == 0) next_y[i]--;
			if(trial_route[i] == 1) next_x[i]--;
			if(trial_route[i] == 2) next_y[i]++;
			if(trial_route[i] == 3) next_x[i]++;
			if(!army[target].getforest_perceived(next_x[i], next_y[i])) step_okay = false;
			else {
				for(int k = 0; k < i; k++) {
					if(next_x[k] == next_x[i] && next_y[k] == next_y[i] && k != i) step_okay = false;
				}
				if(step_okay && next_x[i] == x && next_y[i] == y) step_okay = false;
				if(step_okay && i >= 2) {
					boolean hook = false;
					if(trial_route[i] == 2 && trial_route[i-1] == 1 && trial_route[i-2] == 0) hook = true;	
					if(trial_route[i] == 2 && trial_route[i-1] == 3 && trial_route[i-2] == 0) hook = true;
					if(trial_route[i] == 3 && trial_route[i-1] == 2 && trial_route[i-2] == 1) hook = true;
					if(trial_route[i] == 3 && trial_route[i-1] == 0 && trial_route[i-2] == 1) hook = true;	
					if(trial_route[i] == 1 && trial_route[i-1] == 2 && trial_route[i-2] == 3) hook = true;	
					if(trial_route[i] == 1 && trial_route[i-1] == 0 && trial_route[i-2] == 3) hook = true;	
					if(trial_route[i] == 0 && trial_route[i-1] == 1 && trial_route[i-2] == 2) hook = true;	
					if(trial_route[i] == 0 && trial_route[i-1] == 3 && trial_route[i-2] == 2) hook = true;
					if(hook) step_okay = false;
				}
			}
			boolean at_exit = false;
			if(next_x[i] == army[target].getforest_exit_perceived_x() && next_y[i] == army[target].getforest_exit_perceived_y()) at_exit = true; 
			if(!step_okay || at_exit || (step_okay && i == i_step_limit && !at_exit)) {
				if(at_exit) {
					if(i == 0) break pathfind;
					if(i_step_limit > i - 1) {
						i_step_limit = i;
						best_route = trial_route.clone();
					    if(i < 14) best_route[i+1] = 8;
						if(i == 1) break pathfind;
					}
				}
				counter: for(int j = i; j >= 0; j--) {
					if(j == 0) {
						next_x[j] = x;
						next_y[j] = y;
					}
					else {
						next_x[j] = next_x[j-1];
						next_y[j] = next_y[j-1];
					}
					trial_route[j]++;
					if(trial_route[j] > 3) trial_route[j] = trial_route[j] - 4;
					if(trial_route[j] != 0) break counter;
					if(i != 0) i--;
					if(j == 0 && trial_route[j] == 0) still_working = false;
				} 
				for(int j = i+1; j < 15; j++) {
					trial_route[j] = 0;
				}	
				i--;
			}
			else {
				if(i < 14) {
					next_x[i+1] = next_x[i];
					next_y[i+1] = next_y[i];
				}					
			}
		} while (still_working);
		
		String bird_report = "";
		for(int q = 0; q < 15; q++) {
			if(best_route[q] == -1 || best_route[q] == 8) break;
			if(best_route[q] == 0) bird_report = bird_report + "N";
			if(best_route[q] == 1) bird_report = bird_report + "W";
			if(best_route[q] == 2) bird_report = bird_report + "S";
			if(best_route[q] == 3) bird_report = bird_report + "E";
		}
		if(target != user) army[target].setbird_report(bird_report);
		bird_report = bird_report + "!";
		
		if(best_route[0] != -1) {
			if(bbtext == 3) {
				if(watch_stars) masterStringOut("*** 14053");
				else masterStringOut("***");
				masterStringOut("You see a streak of blue race through the trees. A little bird flutters around your head, its feathers strangely brilliant in the rotting green darkness.");
				hitEnter(14329);
				masterStringOut("It alights on your shoulder and frantically speaks in your ear:");
				Wait.manySec(2);
				masterStringOut("\""+bird_report+"\"");
				Wait.manySec(2);
				masterStringOut("It is gone.");
			}
			if(bbtext == 1 || bbtext == 2) {
				String insert_name = "";
				if(army[user].getfriend(target) > -1) masterStringOut("A bluebird flutters near "+army[target].getname()+"'s ear... it seems to be speaking to him!");
				else masterStringOut("A bluebird flutters near a nearby stranger's ear... it seems to be speaking to him!");
			}
		}
	}
			
	public void wizardEncounter(int target) {
	
		boolean go_ahead = true;
		if(army[target].getincantation(0) != -1) {
			boolean found_another = false;
			for(int t = 0; t < armysize; t++) {
				if(target != t && army[t].getx() == army[target].getx() && army[t].gety() == army[target].gety() && army[t].getincantation(0) == -1) {
					found_another = true;
					target = t;
					break;
				}
			}
			if(!found_another) go_ahead = false;
		}
	
		if(go_ahead) {
			String who_a = army[target].getname();
			if(target == user) who_a = "you";
			String who_b = who_a;
			if(army[user].getfriend(target) < 0) {
				who_a = "a nearby stranger";
				who_b = "the stranger";
			}
	
			int word_a = -1; 
			int word_b = -1; 
			int word_c = -1; 
	
			do {
				word_a = dice.throwdice(1,20) - 1;
				word_b = dice.throwdice(1,20) - 1;
				word_c = dice.throwdice(1,20) - 1;
			} while (word_a == word_b || word_b == word_c || word_c == word_a); 			
			
			army[target].setincantation(word_a, word_b, word_c);
			
			if(samePlace(user, target) && army[user].gethealth() > 0) {
				masterStringOut("A man leaps out of the darkness!"); 
				hitEnter(14385);
				masterStringOut("He approaches "+who_a+"... his long hair waves slowly, as though he were underwater...");
				Wait.manySec(4);
				masterStringOut("...his clothing gathers the air, and flaps violently...");
				Wait.manySec(3);
				masterStringOut("... he locks his colorless eyes on "+who_b+", and in a grim voice, says...");   
				Wait.manySec(3);
				masterStringOut("\""+incantations[word_a]+" "+incantations[word_b]+" "+incantations[word_c]+"\"");
				Wait.manySec(3);
				masterStringOut("He lifts off the ground and disappears in the trees.");
				hitEnter(14395);
			}
		}
	}
	
	public void spiritEncounter(int target) {
		int spirittext = 0;
		if(samePlace(user, target)) spirittext = 1;
		if(user == target) spirittext = 3;
		
		int t_row = getWarRowFromArmyIndex(target);
		int another_rewarded = -1;
		ArrayList<Integer> those_rewarded = new ArrayList<Integer>(); 
		if(t_row > -1) {
			for(int i = 0; i < number_of_columns; i++) {
				if(war[t_row][i] > -1) {
					if(army[war[t_row][i]].gethealth() > 0 && army[war[t_row][i]].ishere(battle_x, battle_y) && !out_of_the_fight[t_row][i]) {
						if(war[t_row][i] == user && user != target) spirittext = 2;
						if(war[t_row][i] != user) another_rewarded = war[t_row][i];
						those_rewarded.add(war[t_row][i]);
					}
				}
			}
			
			if(those_rewarded.size() > 0) {
				if(spirittext > 1) {
					masterStringOut("There is a shudder above you, in the tree tops... and points of soft blue light drift down like snow.");
					Wait.manySec(3);
					masterStringOut("A voice whispers...");
					Wait.manySec(2);
					masterStringOut("\"You are a friend to these woods... please, take these gifts... may you end our plight!\"");
					Wait.manySec(2);
					masterStringOut("You feel you've become more powerful, somehow.");
					if(those_rewarded.size() == 2) {
						if(another_rewarded > -1) {
							if(army[user].getfriend(another_rewarded) > -1) masterStringOut(army[another_rewarded].getname()+" has also received the offering.");
							else masterStringOut("A stranger here has also received the offering.");
							masterStringOutWithNameIfKnown(another_rewarded, "\"Aaaaahhhhhh.....\"");
						}
					}
					if(those_rewarded.size() > 2) {
						masterStringOut("Others here, too, have received the offering.");
						masterStringOutWithNameIfKnown(another_rewarded, "\"Aaaaahhhhhh.....\"");
					}
					hitEnter(20433);
				}
				if(spirittext == 1) {
					String lights_message = "Soft blue lights are drifting down on ";
					if(army[user].getfriend(target) > -1) {
						lights_message += army[target].getname();
						if(those_rewarded.size() == 2) lights_message += " and his friend";
						if(those_rewarded.size() > 2) lights_message += " and his group";
					}
					else {
						if(those_rewarded.size() == 1) lights_message += " a stranger";
						else lights_message += " a gang";
					} 
					lights_message += " nearby. A whispering voice is faintly heard.";
					masterStringOut(lights_message);
					masterStringOutWithNameIfKnown(target, "\"Aaaaahhhhhh.....\"");
				}
				
				int power_choice = dice.throwdice(1, 3);
				for(int i = 0; i < those_rewarded.size(); i++) {
					if(power_choice == 1) army[those_rewarded.get(i)].changestrength(1);
					if(power_choice == 2) army[those_rewarded.get(i)].changespeed(1);
					if(power_choice == 3) army[those_rewarded.get(i)].changemaxhealth(15);
					army[those_rewarded.get(i)].full_heal();
					army[those_rewarded.get(i)].setmorale(40);
					army[those_rewarded.get(i)].setnumber_of_forest_spirit_credits(0);
				}
			}
		}
	}

	public int[] borderSpot() {
		int[] borderspot = new int[2];
		borderspot[0] = 1;
		borderspot[1] = 1;
		int side = dice.throwdice(1, 4);
		if(side == 0) {
			borderspot[1] = 1;
			borderspot[0] = dice.throwdice(1, boardside);
		} 	
		if(side == 1) {
			borderspot[1] = boardside;
			borderspot[0] = dice.throwdice(1, boardside);
		} 	
		if(side == 2) {
			borderspot[0] = 1;
			borderspot[1] = dice.throwdice(1, boardside);
		} 	
		if(side == 3) {
			borderspot[0] = boardside;
			borderspot[1] = dice.throwdice(1, boardside);
		} 	
	
		return borderspot;
	
	}
	
	public boolean checkIfMoveIsValid(int subject, int x_delta, int y_delta) {
		int newx = army[subject].getx() + x_delta;
		int newy = army[subject].gety() + y_delta;
		boolean all_clear = true;
		if(newx < 0 || newy < 0) all_clear = false;
		if(newx > boardside && newx < boardside + 3) all_clear = false;
		if(newy > boardside && newy < boardside + 3) all_clear = false;
		if(newx > boardside + 8 || newy > boardside + 8) all_clear = false;
		if(all_clear && newx > boardside && newy > boardside) {
			if(!army[subject].getforest_perceived(newx - boardside - 3, newy - boardside - 3)) all_clear = false;
		}
		return all_clear;
	}
	
	public int[] randomRunaway(int pinto) {
		int random_runaway = dice.throwdice(1, 4);
		int runxchange = 0;
		int runychange = 0;
		if(pinto != -1) {
			if(!army[pinto].in_the_forest()) {
				if(!(army[pinto].getx() == forest_entry_x && army[pinto].gety() == forest_entry_y)) {
					boolean move_okay = false;
					do {
						random_runaway = dice.throwdice(1, 4);
						if(random_runaway == 1 && army[pinto].getx() - 1 > 0) {
							runxchange = -1;
							move_okay = true;
						}
						if(random_runaway == 2 && army[pinto].getx() + 1 <= boardside) {
							runxchange = 1;
							move_okay = true;
						}
						if(random_runaway == 3 && army[pinto].gety() - 1 > 0) {
							runychange = -1;
							move_okay = true;
						}
						if(random_runaway == 4 && army[pinto].gety() + 1 <= boardside) {
							runychange = 1;
							move_okay = true;
						}
					} while (!move_okay);
				}
				else {
					boolean move_okay = false;
					do {
						random_runaway = dice.throwdice(1, 4);
						if(random_runaway == 1 && army[pinto].getx() - 1 > 0 || forest_direction.compareToIgnoreCase("west") == 0) {
							runxchange = -1;
							move_okay = true;
						}
						if(random_runaway == 2 && army[pinto].getx() + 1 <= boardside || forest_direction.compareToIgnoreCase("east") == 0) {
							runxchange = 1;
							move_okay = true;
						}
						if(random_runaway == 3 && army[pinto].gety() - 1 > 0 || forest_direction.compareToIgnoreCase("north") == 0) {
							runychange = -1;
							move_okay = true;
						}
						if(random_runaway == 4 && army[pinto].gety() + 1 <= boardside || forest_direction.compareToIgnoreCase("south") == 0) {
							runychange = 1;
							move_okay = true;
						}
					} while (!move_okay);
				}
			}
			else {
				switch (random_runaway) {
					case 1:
						if(army[pinto].getx() < 18) {
							if(army[pinto].getforest_perceived(army[pinto].getx() + 1 - boardside - 3, army[pinto].gety() - boardside - 3)) {
								runxchange = 1;
								break;
							}
						}
					case 2:
						if(army[pinto].getx() > 13) {
							if(army[pinto].getforest_perceived(army[pinto].getx() - 1 - boardside - 3, army[pinto].gety() - boardside - 3)) {
								runxchange = -1;
								break;
							}
						}
					case 3:
						if(army[pinto].gety() < 18) {
							if(army[pinto].getforest_perceived(army[pinto].getx() - boardside - 3, army[pinto].gety() + 1 - boardside - 3)) {
								runychange = 1;
								break;
							}
						}
					case 4:
						if(army[pinto].gety() > 13) {
							if(army[pinto].getforest_perceived(army[pinto].getx() - boardside - 3, army[pinto].gety() - 1 - boardside - 3)) runychange = -1;
						}
						else runychange = 1;
						break;
					default: masterStringOut("Wha?  13869");
				}
			}
		}
//		else masterStringOut("**** 20724 pinto == -1 which it should not");
		int[] runchange = new int[2];
		runchange[0] = runxchange;
		runchange[1] = runychange;
		return runchange;
	}
	
	public void moveAlongForestCommuters() {
		for(int i = 0; i < armysize; i++) {
			boolean enter_forest = false;
			boolean exit_forest = false;
			if(army[i].getpotential_x() == forest_entry_x && army[i].getpotential_y() == forest_entry_y + 1 && forest_direction.compareToIgnoreCase("south") == 0) enter_forest = true;
			if(army[i].getpotential_x() == forest_entry_x && army[i].getpotential_y() == forest_entry_y - 1 && forest_direction.compareToIgnoreCase("north") == 0) enter_forest = true;
			if(army[i].getpotential_x() == forest_entry_x + 1 && army[i].getpotential_y() == forest_entry_y && forest_direction.compareToIgnoreCase("east") == 0) enter_forest = true;
			if(army[i].getpotential_x() == forest_entry_x - 1 && army[i].getpotential_y() == forest_entry_y && forest_direction.compareToIgnoreCase("west") == 0) enter_forest = true;
			if(army[i].in_the_forest() && army[i].getpotential_x() - boardside - 3 == army[i].getforest_exit_perceived_x() && army[i].getpotential_y() - boardside - 3 == army[i].getforest_exit_perceived_y()) exit_forest = true;
			if(enter_forest) {
				if(i == user) need_glow_message = true;
				if(!army[i].in_the_forest()) {
					if(i < humansize) enterForest(i);
					else {
						if(army[i].getmasters_number() > -1) {
							if(army[army[i].getmasters_number()].in_the_forest()) army[i].perceive_forest_anew(army[army[i].getmasters_number()].getwhole_forest_perceived(), army[army[i].getmasters_number()].getforest_entry_perceived_x(), army[army[i].getmasters_number()].getforest_entry_perceived_y(), army[army[i].getmasters_number()].getforest_exit_perceived_x(), army[army[i].getmasters_number()].getforest_exit_perceived_y());
						}
						else enterForest(i);
					}
				}
				army[i].setxyquick(army[i].getforest_entry_perceived_x() + boardside + 3, army[i].getforest_entry_perceived_y() + boardside + 3);
//				masterStringOut(army[i].getname()+" entering forest; going to "+(army[i].getforest_entry_perceived_x() + boardside + 3)+", "+(army[i].getforest_entry_perceived_y() + boardside + 3));
			}
			if(exit_forest) {
				if(i == user) forest_aiees.clear();
				moveAlongFCLastBit(i);
			}
		} 
	}
	
	public void moveAlongFCLastBit(int i) {
		army[i].leave_forest();
		army[i].setxyquick(forest_entry_x, forest_entry_y);
		army[i].setnumber_of_forest_spirit_credits(0);
		if(!forest_exit_gangs_celebrating.contains(new Integer(army[i].getaffiliation()))) forest_exit_gangs_celebrating.add(army[i].getaffiliation());
	}	

	
	// Rumor Tools
	
	public void startRumor(String tag) {
		int nextslot = 0;
		boolean already_started = false;
		for(int i = 0; i < 100; i++) {
			if(rumors[i].gettag().compareToIgnoreCase(tag)==0) {
				already_started = true;
				break;
			}
			if(rumors[i].gettag().compareToIgnoreCase("blank")==0) {
				nextslot = i;
				break;
			}
		}
		
		if(!already_started) {
			if(tag.contains("kills")) {
				rumors[nextslot] = new Rumor(humansize, user, tag, true, getNumberFromName(tag.substring(0, tag.length() - 6)), army[getNumberFromName(tag.substring(0, tag.length() - 6))].getgeneration());			
				rumors[nextslot].setbest_kills_of_player_subject(army[getNumberFromName(tag.substring(0, tag.length() - 6))].getkills());
			}
			else rumors[nextslot] = new Rumor(humansize, user, tag, true);
		}

		// if(tag.compareToIgnoreCase("gregor") == 0) rumors[nextslot] = new Rumor(humansize, "gregor", true);
		// if(tag.compareToIgnoreCase("house") == 0) rumors[nextslot] = new Rumor(humansize, "house", true);
		// if(tag.compareToIgnoreCase("pig") == 0) rumors[nextslot] = new Rumor(humansize, "pig", true);
			
	}
	
	public boolean playerReportsRumor(int hailer, int accosted, int encountertext) {
		boolean told = false;
ri_loop:for(int ri = 99; ri >= 0; ri--) {
			if((rumors[ri].has_heard(hailer) && !rumors[ri].knows_knows(hailer, accosted)) || (rumors[ri].has_heard(accosted) && !rumors[ri].knows_knows(accosted, hailer))) {
				int tells = (rumors[ri].has_heard(hailer)) ? hailer : accosted;
				int listens = (rumors[ri].has_heard(hailer)) ? accosted : hailer;
				if(!(listens == user && rumors[ri].user_heard_enough())) {
					if(encountertext > 1) {
						if(tells != user && listens != user) {
							masterStringOut(army[tells].getname()+":  \"Hhhrmm brrm "+getRandomDialogueWord(rumors[ri].gettag())+" brr brr..\"");
							if(rumors[ri].knows_is_false(listens)) masterStringOut(army[listens].getname()+":  \"Mm mm... nope... nope...\"");
							else if(rumors[ri].has_heard(listens)) masterStringOut(army[listens].getname()+":  \"Mm hm... yup... yup...\"");
							else masterStringOut(army[listens].getname()+":  \"Huh...     Interesting...\"");
						}
						else {
							//won't happen if the rumor is about the teller himself- and if the rumor is about the listener, the dialogue will be different. 
							if(rumors[ri].getplayer_subject() != tells) getRumorDialogue(rumors[ri].gettag(), tells, listens);
						}
					}
					told = true;
					rumors[ri].hears_rumor(listens);
					rumorKnowsKnowsMutual(rumors[ri].gettag(), tells, listens);
					if(rumors[ri].knows_is_false(listens)) rumors[ri].now_knows_is_false(tells);
					break ri_loop;
				}
			}
		}
		return told;
	}
	
	public boolean rumorIsKnownBy(String tag, int subject) {
		boolean isknown = false;
		for(int i = 0; i < 100; i++) {
			if(rumors[i].gettag().compareToIgnoreCase(tag) == 0) {
				if(rumors[i].has_heard(subject)) {
					isknown = true;
					break;
				}
			}
		}
		return isknown;
	}
	
	public void rumorIsHeardBy(String tag, int subject, int line) {
		for(int i = 0; i < 100; i++) {
			if(rumors[i].gettag().compareToIgnoreCase(tag) == 0) {
				rumors[i].hears_rumor(subject);
				//if(tag.compareToIgnoreCase("pig")==0) System.out.println("**** from "+line+": "+tag+" hears about pigs"); 
				break;
			}
		}
		if(tag.compareToIgnoreCase("house")==0) {
			for(int i = 0; i < 100; i++) {
				if(rumors[i].gettag().compareToIgnoreCase("gregor") == 0) {
					rumors[i].hears_rumor(subject);
					break;
				}
			}
		}
	}
	
	public void rumorKnowsKnows(String tag, int know_1, int know_2) {
//		if(know_1 == user || know_2 == user) System.out.println("**** 21650 knowsknows is happening. tag is "+tag+", know_1 is "+know_1+", know_2 is "+know_2);
		for(int i = 0; i < 100; i++) {
			if(rumors[i].gettag().compareToIgnoreCase(tag) == 0) {
				rumors[i].now_knows_knows(know_1, know_2);
				break;
			}
		}
		if(tag.compareToIgnoreCase("house")==0) {
			for(int i = 0; i < 100; i++) {
				if(rumors[i].gettag().compareToIgnoreCase("gregor") == 0) {
					rumors[i].now_knows_knows(know_1, know_2);
					break;
				}
			}
		}		
	}
	
	public void rumorKnowsKnowsMutual(String tag, int know_1, int know_2) {
		rumorKnowsKnows(tag, know_1, know_2);
		rumorKnowsKnows(tag, know_2, know_1);
	}
	
	public void getRumorDialogue(String tag, int speaker, String listener) {
		getRumorDialogue(tag, speaker, -1);
	}
	public void getRumorDialogue(String tag, String speaker, int listener) {
		getRumorDialogue(tag, -1, listener);
	}
	public void getRumorDialogue(String tag, int sp, int lis) {
		int rumor = 0;
		for(int i = 0; i < 100; i++) {
			if(rumors[i].gettag().compareToIgnoreCase(tag) == 0) {
				rumor = i;
				break;
			}
		}
		
		String speaker;
		String listener;
		if(sp > -1) speaker = army[sp].getname();
		else speaker = "GREGOR";
		if(lis > -1) listener = army[lis].getname();
		else listener = "Gregor";
		
		if(tag.compareToIgnoreCase("house")==0) {
			if(sp == user) masterStringOut("You chat with "+listener+", and you end up telling him the location of the longhouse.");
			if(lis == user) masterStringOut(speaker+":  \""+getNupDialogue(tag, 0) + getDirection(army[lis].getx(), army[lis].gety(), markers[0][0], markers[1][0]) +getNupDialogue(tag, 1) +"\"");
		}

		if(tag.compareToIgnoreCase("gregor")==0) {
			if(sp == user) masterStringOut("You chat with "+listener+", and you end up telling him what you've heard about Gregor.");
			if(lis == user) masterStringOut(speaker+":  \""+getNupDialogue(tag, 0)+"\"");
		}
			
		if(tag.compareToIgnoreCase("pig")==0) {
			if(sp == user) masterStringOut("You chat with "+listener+", and you end up describing to him how to keep a drink in a pig's bladder.");
			if(lis == user) masterStringOut(speaker+":  \""+getNupDialogue(tag, 0)+"\"");
		}
		
		if(tag.compareToIgnoreCase("forest")==0) {
			if(sp == user) masterStringOut("You chat with "+listener+", and you end up repeating what you heard about the forest.");
			if(lis == user) {
				if(sp > -1) masterStringOut(speaker+":  \""+getNupDialogue(tag, 0)+"\"");
				else masterStringOut(speaker+":  \"Beware the forest. There's a wide curse on it, and you've got to be prepared to survive it. But if you meet a good spirit in there, it'd be grateful to see you.\"");
			}
		}

		if(tag.compareToIgnoreCase("cave")==0) {
			if(sp == user) masterStringOut("You chat with "+listener+", and you end up relating what you know about the mysterious cave.");
			if(lis == user) {
				if(sp > -1) masterStringOut(speaker+":  \""+getNupDialogue(tag, 0)+"\"");
				else masterStringOut(speaker+":  \"There's a cave in this land. A dangerous place, but if the rumors are true, there's a passage in there that'll take you out of this place. I might try some day. They also say that meat helps you find it.\"");
			}
		}

		if(tag.contains("kills")) {
			//trouble: the player subject might be a previous generation of this army position number.
			int dc = rumors[rumor].getplayer_subject();
			//to get the kills, we could look this person up in the graveyard.
			int deadly_cur_kills = army[rumors[rumor].getplayer_subject()].getkills();
			if(rumors[rumor].getgeneration_of_player_subject() != army[dc].getgeneration()) deadly_cur_kills = rumors[rumor].getbest_kills_of_player_subject();
			else rumors[rumor].setbest_kills_of_player_subject(deadly_cur_kills);
			//to get the name, we just add the name without number to the generation.
			String deadly_cur = army[dc].getname_without_number();
			deadly_cur += (" "+rumors[rumor].getgeneration_of_player_subject());
			//here we ensure that we are comparing the actual rumor subject with the speaker and listener.
			//(actually it doesn't matter- we want to avoid all of this if the speaker or listener are ANY generation of the player subject.)
			if(dc != sp && dc != lis && sp > -1 && dc > -1) {
				if(army[sp].getfriend(dc) < 0 && army[lis].getfriend(dc) < 0) {
					if(sp == user) masterStringOut("You chat with "+listener+", and you mention how deadly you've heard this "+deadly_cur+" person is.");
					if(lis == user) masterStringOut(speaker+":  \""+getNupDialogue(tag, 0) + deadly_cur + getNupDialogue(tag, 1) + deadly_cur_kills + getNupDialogue(tag, 2)+"\"");
				}
				else if(army[lis].getfriend(dc) < 0) {
					if(sp == user) masterStringOut("You chat with "+listener+", and you mention how deadly you've heard "+deadly_cur+" is.");
					if(lis == user) masterStringOut(speaker+":  \""+getNupDialogue(tag, 3) + deadly_cur + getNupDialogue(tag, 4) + deadly_cur_kills + getNupDialogue(tag, 2)+"\"");
				}
				else {
					if(sp == user) masterStringOut("You chat with "+listener+", and you mention how deadly you've heard "+deadly_cur+" is.");
					if(lis == user) masterStringOut(speaker+":  \""+getNupDialogue(tag, 5) + deadly_cur + getNupDialogue(tag, 6) + deadly_cur_kills + getNupDialogue(tag, 2)+"\"");
				}
			}
			//same again, ensure an appropriate comparison.
			else if(dc == lis && army[dc].getgeneration() == rumors[rumor].getgeneration_of_player_subject()) {
				if(sp == user) {
					masterStringOut("You tell "+listener+" that you've heard how deadly he is.");
					masterStringOut(listener+":  \"Dead to rights, friend.\"");
				}
				if(lis == user) masterStringOut(speaker+":  \"I heard you've killed about "+deadly_cur_kills+" men, "+listener+". What gets you in all that trouble? Is it your face?\"");
			} 
		}

		if(rumors[rumor].knows_is_false(lis)) {
			if(rumors[rumor].getplayer_subject() == -1) {
				masterStringOut(listener+": \"Nah... I believe that's a false rumor.\"");
				masterStringOut(speaker+": \"Huh...\"");
			}
			else {
				masterStringOut(listener+": \"No... I believe he's dead, actually.\"");
				masterStringOut(speaker+": \"Oh...\"");
			}
		}
		
		if(lis == user) hitEnter(21116);
		
	}
	
	public String getNupDialogue(String tag, int index) {
		String nup_out = "";
		if(tag.compareToIgnoreCase("house")==0) {
			if(index == 0) nup_out = "I suppose you've heard of Gregor... you should pay him a visit some time. He lives ";
			if(index == 1) nup_out = " of here.";
		}
		if(tag.compareToIgnoreCase("gregor")==0) nup_out = "Have you heard of Gregor? I've heard that he lives somewhere around here.";
		if(tag.compareToIgnoreCase("pig")==0) nup_out = "Did you ever use a pig's bladder before? Works kind of like a bottle. They don't last, though.";
		if(tag.compareToIgnoreCase("forest")==0) nup_out = "That death trap of a forest- it's a cursed place, but I heard it's haunted by good spirits, too.";
		if(tag.compareToIgnoreCase("cave")==0) nup_out = "I heard there's a cave hidden around here. The cave has a way out of here. Although I don't really know what IS out of here... Also, meat is supposed to help you find it somehow. Yeah, meat. That's what I heard.";
		if(tag.contains("kills")) {
			if(index == 0) nup_out = "I heard there's a fellow named ";
			if(index == 1) nup_out = " killed upwards of ";
			if(index == 2) nup_out = " men.";
			if(index == 3) nup_out = "I know a fellow named ";
			if(index == 4) nup_out = "- they say he's killed upwards of ";
			if(index == 5) nup_out = "You know how deadly that ";
			if(index == 6) nup_out = " fellow is? He's killed upwards of ";
		}
		return nup_out;
	}
	
	public void resetRumorsFor(int erased) {
		for(int i = 0; i < 100; i++) {
			rumors[i].clear_all_for_this_soul(erased);
		}
	}
	
	public String getRandomDialogueWord(String tag) {
		String word_out = "";
		String[] words_in = getNupDialogue(tag, 0).split(" ");
		int word_choice_index = dice.throwdice(1, words_in.length) - 1;
		word_out = words_in[word_choice_index];
		return word_out;
	}
	
	// Short Events + Tools

	public void dropNewApple(int applex, int appley) {
		for(int bomb = 0; bomb < 20; bomb++) {
			if(!items[3][bomb].is_usable() || !items[3][bomb].is_visible() || !items[3][bomb].is_obtainable()) {
				items[3][bomb].set_drop_point(applex, appley);
				items[3][bomb].start_item(turnclock);
				break;
			}
		}
	}
	
	public int appleOwnershipCount(int person) {
		int appcount = 0;
		for(int j = 0; j < items[3].length; j++) {
			if(items[3][j].is_a_okay()) {
				if(items[3][j].getowner() == person) appcount++;
			}
		}
		return appcount;
	}

	public int appleOwnershipSingle(int person) {
		int apple_to_use = -1;
		for(int j = 0; j < items[3].length; j++) {
			if(items[3][j].is_a_okay()) {
				if(items[3][j].getowner() == person) {
					apple_to_use = j;
					break;
				}
			}
		}
		return apple_to_use;
	}

	public boolean fillVessel(String liquid) {
		boolean input_valid = false;
		if(liquid.compareToIgnoreCase("pond") == 0) {
			masterStringOut("\nGreen bits swirl lazily on the surface of the pond. Deeper, there are red and purple hues, and maybe something swimming around, but it's hard to tell.");
			if(dice.throwdice(1,3)==1) {
				Wait.manySec(2);
				pondVision();
			}
		}
		if(liquid.compareToIgnoreCase("fount") == 0) masterStringOut("\nThe water looks clean enough.");
		boolean will_drink = false;
		boolean will_fill = false;
		String drink_choice = "";
		if(drinkCount("empty bottles") > 0 || drinkCount("empty bladders") > 0) {
			String riv_choice = "Do you want to... \n  ...take a drink? ";
			if(drinkCount("empty bottles") > 0) riv_choice += "\n  ...fill a bottle?";
			if(drinkCount("empty bladders") > 0) riv_choice += "\n  ...fill a bladder?";
			masterStringOut(riv_choice+"\n");
			boolean dc_input_valid = false;
			do {
				if(drinkCount("empty bottles") == 0 || drinkCount("empty bladders") == 0) {
					masterStringOut("[  Drink      Fill                           Exit        ]");
				}
				else masterStringOut("[  Drink      Bottle      Bladder            Exit        ]");

				drink_choice = stringInput();
			
				if (drink_choice.compareToIgnoreCase("drink") == 0) dc_input_valid = true;
				if (drink_choice.compareToIgnoreCase("fill") == 0 && (drinkCount("empty bottles") == 0 || drinkCount("empty bladders") == 0)) dc_input_valid = true;
				if (drink_choice.compareToIgnoreCase("bottle") == 0 && drinkCount("empty bottles") > 0) dc_input_valid = true;
				if (drink_choice.compareToIgnoreCase("bladder") == 0 && drinkCount("empty bladders") > 0) dc_input_valid = true;
				if (drink_choice.compareToIgnoreCase("exit") == 0) dc_input_valid = true;

			}while (!dc_input_valid); 

			if(drink_choice.compareToIgnoreCase("drink") == 0) will_drink = true;
			if(drink_choice.compareToIgnoreCase("fill") == 0 || drink_choice.compareToIgnoreCase("bottle") == 0 || drink_choice.compareToIgnoreCase("bottle") == 0) will_fill = true;
		}
		else {
			if(liquid.compareToIgnoreCase("pond") == 0) masterStringOut("Do you drink from the pond?\n");
			if(liquid.compareToIgnoreCase("fount") == 0) masterStringOut("Do you drink from the rivulet?\n");
			String yn_choice = ynChoice();
			if(yn_choice.compareToIgnoreCase("y") == 0) will_drink = true;
		}
		if(will_drink) {
			if(liquid.compareToIgnoreCase("pond") == 0) masterStringOut("\nYou scoop the strange water and raise it to your lips...");
			if(liquid.compareToIgnoreCase("fount") == 0) masterStringOut("\nYou slurp a mouthful of water. Wow, that's cold!");
			Wait.manySec(1);
			if(liquid.compareToIgnoreCase("pond") == 0) antidote(user);
			input_valid = true;
		}
		if(will_fill) {
			if(drink_choice.compareToIgnoreCase("bottle") == 0 || drinkCount("empty bottles") > 0) {
				if(liquid.compareToIgnoreCase("fount") == 0) masterStringOut("\nYou fill a bottle with cold, clear water.");
				if(liquid.compareToIgnoreCase("pond") == 0) masterStringOut("\nYou dunk an empty bottle in the pond. It comes up full of murky water.");
find_empty:		for(int atb = 0; atb < items[4].length; atb++) {
					if(items[4][atb].getowner() == user && !items[4][atb].is_full()) {
						items[4][atb].fill(liquid);
						input_valid = true;
						break find_empty;
					}
				}
			}
			else {
				if(liquid.compareToIgnoreCase("pond") == 0) masterStringOut("\nYou dunk an empty bladder in the pond. It comes up full and cold, and a shade darker.");
				if(liquid.compareToIgnoreCase("fount") == 0) masterStringOut("\nYou fill a bladder with cold, clear water. Wonder how long it'll hold it?");
				army[user].fill_bladder(liquid);
				input_valid = true;
			}
		}
		return input_valid;		
	}

