										Wait.manySec(2);
										masterStringOut("You see a nearby stranger undergo a terrifying transformation!");
										Wait.manySec(2);
										masterStringOut("He is clearly bigger now than he was before!");
										Wait.manySec(1);
										masterStringOut("\"HA HA HA HAAAAAA!!\"");
