	public void Blessing(int subject) {
	
		int blessingtext = 0;
		if(samePlace(user, subject)) blessingtext = 1;
		if(army[user].getfriend(subject) > -1) blessingtext = 2;
		if(sameGang(user, subject)) blessingtext = 3;
		if(user == subject) blessingtext = 3;
	
		if(blessingtext == 3) Wait.manySec(2);
		else Wait.manySec(1);
		masterStringOut("\n");
		if(watch_stars) masterStringOut("*** 4176");
		else masterStringOut("***");
		masterStringOut("Clouds lift in the sky and the sun warms you. The ill has been set right, somehow. You feel it everywhere."); 
		if(blessingtext == 3) Wait.manySec(3);
		else if(blessingtext == 0) Wait.manySec(1);
		else Wait.manySec(2);
		if(blessingtext == 3) masterStringOut("\nYou look at your hands... your skin glows with a soft light, a sign of someone's (or something's) approval.");
		if(blessingtext == 2) masterStringOut("You notice that "+army[subject].getname()+" is looking at his hands... his skin glows with a soft light... "+army[subject].getname()+" gasps softly, his eyes wide.\n"+army[subject].getname()+" \"My word... it's a blessing!\"");
		if(blessingtext == 1) masterStringOut("You notice a stranger looking at his hands... his skin glows with a soft light... he gasps softly, his eyes wide.\n\"My word... it's a blessing!\"");
		army[subject].zombie_slayer_power_up();
		if(army[subject].getaffiliation() != 0) {
			if(blessingtext == 3) {
				if(numberInGang(user) > 2) masterStringOut("The same thing is happening to your friends...");
				else masterStringOut("The same thing is happening to your companion...");				
				Wait.manySec(3);
			}
			if(blessingtext == 2 || blessingtext == 1) {
				if(numberInGang(subject) > 2) masterStringOut("The same thing is happening to his friends...");
				else masterStringOut("The same thing is happening to his companion...");
				Wait.manySec(1);
			}
			if(blessingtext > 0) {
				for(int z = 0; z < user; z++) {
					if(army[z].getaffiliation() == army[subject].getaffiliation() && army[z].gethealth() > 0) {
						army[z].zombie_slayer_power_up();
						String wowmessage = "";
						if(army[user].getfriend(z) > -1) wowmessage += army[z].getname()+":  ";
						int wowroll = dice.throwdice(1, 8);
						if(wowroll == 1) wowmessage += "\"Wow!\"";
						if(wowroll == 2) wowmessage += "\"Well I never!\"";
						if(wowroll == 3) wowmessage += "\"Look at that!\"";
						if(wowroll == 4) wowmessage += "\"Goodness!\"";
						if(wowroll == 5 || wowroll == 6 || wowroll == 7) wowmessage += "\"It's a blessing!\"";
						if(wowroll == 8) wowmessage += "\"My word!\"";
						masterStringOut(wowmessage);
						Wait.manySec(1);
					}
				}
			}
			army[getLeader(subject)].free_to_move_again();
		}
		if(blessingtext == 3) Wait.manySec(2);
		skeletons_continue = false;

	}
	
	public void Curse(int subject) {
		if(subject == user) {
			masterStringOut("A voice speaks...");
			Wait.manySec(2);
			masterStringOut("\"How disappointing, "+army[user].getname_without_number()+". What a chance you've squandered. Oh well, never mind...(sigh)...\"");
			hitEnter(22693);
		}
		army[subject].receive_curse();
	}
	
	public void eatBrainsAndReport(int subject, int object) {
		if(army[subject].is_zombie()) {
			army[subject].eat_brains();
			army[object].carve_forehead();
			if(subject == user) {
				if(army[user].getbrains_hunger() < -4) masterStringOut("You are still very hungry.");
				if(army[user].getbrains_hunger() == -4) masterStringOut("You are still hungry.");
				if(army[user].getbrains_hunger() == -3) masterStringOut("You are still hungry.");
				if(army[user].getbrains_hunger() == -2) masterStringOut("You are less hungry.");
				if(army[user].getbrains_hunger() == -1) masterStringOut("You are a wee bit hungry, still.");
			}
		}
		if(army[subject].getbrains_hunger() >= 0) zombieRests(subject);
	}

