	public int drinkCount(String tag) {
		//count bottles
		int countbt_empty = 0;
		int countbt_beer = 0;
		int countbt_pond = 0;
		int countbt_fount = 0;
		int countbl_empty = army[user].getnumber_of_empty_bladders();
		int countbl_beer = 0;
		int countbl_pond = 0;
		int countbl_fount = 0;
		int drink_options = 0;
		for(int bt = 0; bt < items[4].length; bt++) {
			if(items[4][bt].getowner() == user) {
				if(items[4][bt].is_full()) {
					if(items[4][bt].get_contents().compareToIgnoreCase("beer") == 0) {
						countbt_beer++;
						if(countbt_beer == 1) drink_options++;
					}
					if(items[4][bt].get_contents().compareToIgnoreCase("pond") == 0) {
						countbt_pond++;
						if(countbt_pond == 1) drink_options++;
					}
					if(items[4][bt].get_contents().compareToIgnoreCase("fount") == 0) {
						countbt_fount++;
						if(countbt_fount == 1) drink_options++;
					}
				}
				else countbt_empty++;
			}
		}
		//bladders.
		for(int bl = 0; bl < army[user].getnumber_of_bladders(); bl++) {
			if(army[user].getcontents_of_certain_bladder(bl).compareToIgnoreCase("beer")==0) countbl_beer++;
			if(army[user].getcontents_of_certain_bladder(bl).compareToIgnoreCase("pond")==0) countbl_pond++;
			if(army[user].getcontents_of_certain_bladder(bl).compareToIgnoreCase("fount")==0) countbl_fount++;
		}	
		if(army[user].hasbladder_of("beer")) drink_options++;
		if(army[user].hasbladder_of("pond")) drink_options++;
		if(army[user].hasbladder_of("fount")) drink_options++;
		
		if(tag.compareToIgnoreCase("bottles of beer")==0) return countbt_beer;
		else if(tag.compareToIgnoreCase("bottles of pond")==0) return countbt_pond;
		else if(tag.compareToIgnoreCase("bottles of fount")==0) return countbt_fount;
		else if(tag.compareToIgnoreCase("bladders of beer")==0) return countbl_beer;
		else if(tag.compareToIgnoreCase("bladders of pond")==0) return countbl_pond;
		else if(tag.compareToIgnoreCase("bladders of fount")==0) return countbl_fount;
		else if(tag.compareToIgnoreCase("beer")==0) return countbt_beer + countbl_beer;
		else if(tag.compareToIgnoreCase("pond")==0) return countbt_pond + countbl_pond;
		else if(tag.compareToIgnoreCase("fount")==0) return countbt_fount + countbl_fount;
		else if(tag.compareToIgnoreCase("empty bottles")==0) return countbt_empty;
		else if(tag.compareToIgnoreCase("empty bladders")==0) return countbl_empty;
		else if(tag.compareToIgnoreCase("drink options")==0) return drink_options;
		else return 0;
	}

