	public String drinkMenu(int drinker) {
		String menu_input = "";
		boolean input_valid = false;
		int countbt_empty = 0;
		int countbt_beer = 0;
		int countbt_pond = 0;
		int countbt_fount = 0;
		int drink_options = 0;
		for(int bt = 0; bt < items[4].length; bt++) {
			if(items[4][bt].getowner() == user) {
				if(items[4][bt].is_full()) {
					if(items[4][bt].get_contents().compareToIgnoreCase("beer") == 0) {
						countbt_beer++;
						if(countbt_beer == 1) drink_options++;
					}
					if(items[4][bt].get_contents().compareToIgnoreCase("pond") == 0) {
						countbt_pond++;
						if(countbt_pond == 1) drink_options++;
					}
					if(items[4][bt].get_contents().compareToIgnoreCase("fount") == 0) {
						countbt_fount++;
						if(countbt_fount == 1) drink_options++;
					}
				}
				else countbt_empty++;
			}
		}
		//bladders.
		if(army[user].hasbladder_of("beer")) drink_options++;
		if(army[user].hasbladder_of("pond")) drink_options++;
		if(army[user].hasbladder_of("fount")) drink_options++;

		String drink_choice = "";					
		String bottles_here = "";
		String add_to_bottles_here = "";
		String letters_bottles_here = "";
		String add_to_letters_bottles_here = "";
		String bottle_choice = null;
		int number_of_bottles_marked = 0;
		int b_print_counter = 0;
		
		if(drink_options == 1) bottle_choice = "a";

		if(drink_options > 1) {
			if(drinker == user) masterStringOut("What do you want to drink? (letter)");
			else masterStringOut("Which drink do you want to offer? (letter)");
		}
		ArrayList<String> drink_lines = new ArrayList<String>();
		for(int atb = 0; atb < items[4].length; atb++) {
			if(items[4][atb].getowner() == user && items[4][atb].is_full()) {
		 		if(items[4][atb].get_contents().compareToIgnoreCase("beer") == 0) add_to_bottles_here = "bottle (beer)";
				if(items[4][atb].get_contents().compareToIgnoreCase("pond") == 0) add_to_bottles_here = "bottle (murky water)";
				if(items[4][atb].get_contents().compareToIgnoreCase("fount") == 0) add_to_bottles_here = "bottle (clear water)";
				add_to_letters_bottles_here = "(" + getAlphabet(number_of_bottles_marked) + ".)";
				number_of_bottles_marked++;
				int extra_spaces_bottles_here = add_to_bottles_here.length() + 6 - add_to_letters_bottles_here.length();
				for(int z = 0; z < extra_spaces_bottles_here; z++) {
					add_to_letters_bottles_here = add_to_letters_bottles_here + " ";
				} 
				bottles_here += add_to_bottles_here + "      ";
			    letters_bottles_here += add_to_letters_bottles_here;
				b_print_counter++;
				if(b_print_counter == 4 || number_of_bottles_marked == countbt_beer + countbt_pond + countbt_fount) {
					drink_lines.add(bottles_here);
					drink_lines.add(letters_bottles_here);
					bottles_here = "";
					letters_bottles_here = "";
					b_print_counter = 0;
				}
			}
		}
		//bladders...
		for(int atb = 0; atb < army[user].getnumber_of_bladders(); atb++) {
	 		if(army[user].is_certain_bladder_full(atb)) {
				if(army[user].getcontents_of_certain_bladder(atb).compareToIgnoreCase("beer")==0) add_to_bottles_here = "bladder (beer)";
				if(army[user].getcontents_of_certain_bladder(atb).compareToIgnoreCase("pond")==0) add_to_bottles_here = "bladder (murky water)";
				if(army[user].getcontents_of_certain_bladder(atb).compareToIgnoreCase("fount")==0) add_to_bottles_here = "bladder (clear water)";
				add_to_letters_bottles_here = "(" + getAlphabet(number_of_bottles_marked) + ".)";
				number_of_bottles_marked++;
				int extra_spaces_bottles_here = add_to_bottles_here.length() + 6 - add_to_letters_bottles_here.length();
				for(int z = 0; z < extra_spaces_bottles_here; z++) {
					add_to_letters_bottles_here = add_to_letters_bottles_here + " ";
				} 
				bottles_here += add_to_bottles_here + "      ";
			    letters_bottles_here += add_to_letters_bottles_here;
				b_print_counter++;
				if(drink_options > 1 && (b_print_counter == 4 || number_of_bottles_marked == countbt_beer + countbt_pond + countbt_fount + army[user].getnumber_of_bladders() - army[user].getnumber_of_empty_bladders())) {
					drink_lines.add(bottles_here);
					drink_lines.add(letters_bottles_here);
					bottles_here = "";
					letters_bottles_here = "";
					b_print_counter = 0;
				}
			}
		}
			
		if(drink_options > 1) {
			for(int atb_out = 0; atb_out < drink_lines.size(); atb_out++) {
				masterStringOut(drink_lines.get(atb_out));
			}
			masterStringOut("\n\n\n");
			boolean got_one_to_drink = false;
			do {
				bottle_choice = stringInput();
				for(int y = 0; y < number_of_bottles_marked; y++) {
					if(bottle_choice.compareToIgnoreCase(getAlphabet(y)) == 0) {
						got_one_to_drink = true;
						input_valid = true;
						break;
					}
				}
			} while(!got_one_to_drink);
		}
		
		int count_bottles_again = 0;
		for(int atb = 0; atb < items[4].length; atb++) {
			if(items[4][atb].getowner() == user) {
				if(getAlphabet(count_bottles_again).compareToIgnoreCase(bottle_choice) == 0) {
					if(items[4][atb].get_contents().compareToIgnoreCase("beer") == 0) {
						input_valid = true;
						menu_input = "bottle of beer";
					}
					if(items[4][atb].get_contents().compareToIgnoreCase("pond") == 0) {
						input_valid = true;
						menu_input = "bottle of murky water";
					}
					if(items[4][atb].get_contents().compareToIgnoreCase("fount") == 0) {
						input_valid = true;
						menu_input = "bottle of clear water";
					}
				}
				count_bottles_again++;
			}
		}
		if(!input_valid) {
			for(int atb = 0; atb < army[user].getnumber_of_bladders(); atb++) {
		 		if(army[user].is_certain_bladder_full(atb)) {
					if(getAlphabet(count_bottles_again).compareToIgnoreCase(bottle_choice) == 0) {							
						if(army[user].getcontents_of_certain_bladder(atb).compareToIgnoreCase("beer")==0) {
							input_valid = true;
							menu_input = "bladder of beer";
						}
						if(army[user].getcontents_of_certain_bladder(atb).compareToIgnoreCase("pond")==0) {
							input_valid = true;
							menu_input = "bladder of murky water";
						}
						if(army[user].getcontents_of_certain_bladder(atb).compareToIgnoreCase("fount")==0) {
							input_valid = true;
							menu_input = "bladder of clear water";
						}
					}
					count_bottles_again++;
				}
			}
		}
		if(!input_valid) menu_input = "invalid";
		return menu_input;				
	}
	
	public boolean drinkEffects(String thing_to_drink, int drinker, int owner) {
		String contents = "";
		boolean input_valid = true;
		if(thing_to_drink.compareToIgnoreCase("invalid")==0) input_valid = false;
		if(thing_to_drink.contains("beer")) {
			if(drinker == user) masterStringOut("\nYou drink the amazing beer. Now you're ready for anything- or at least you think you are!"); 
			else masterStringOutWithNameIfKnown(drinker, "\"Ahh! I'm ready for anything now!\"");
			army[drinker].setmorale(40);
			contents = "beer";
		}
		if(thing_to_drink.contains("murky")) {
			antidote(drinker);
			contents = "pond";
		}
		if(thing_to_drink.contains("clear")) {
			waterWarp(drinker);
			contents = "fount";
		}
		if(thing_to_drink.contains("bottle")) {
			for(int i = 0; i < items[4].length; i++) {
				if(items[4][i].getowner() == owner && items[4][i].get_contents().compareToIgnoreCase(contents) == 0) {
					items[4][i].empty();
				}
			}
		}
		if(thing_to_drink.contains("bladder")) {
			army[owner].lose_bladder(contents);
			if(drinker == user) masterStringOut("That bladder is flimsy- it won't be good for another use. You get rid of it.");
		}
		return input_valid;		
	}

	public boolean drinkMenuAndEffects(int drinker) {
		
		String dchoice = drinkMenu(drinker);
		boolean i_v = drinkEffects(dchoice, drinker, drinker);
		return i_v;
		
	}

